const PART5_MEDIUM = [
  {id:"p5m1",question:"The merger between the two companies _____ pending regulatory approval.",options:["A) remains","B) remain","C) is remaining","D) have remained"],answer:"A",explanation:"'Remains' is correct because the subject 'merger' is singular, and stative verbs like 'remain' require a singular third-person verb in present simple. 'Remain' is wrong because it is the base/plural form and does not agree with the singular subject 'merger'. 'Is remaining' is wrong because 'remain' is a stative verb describing a continuing state, not an action in progress, so the continuous form is unnatural. 'Have remained' is wrong because 'have' is a plural auxiliary and does not agree with the singular subject 'merger'.",category:"Grammar"},
  {id:"p5m2",question:"All expenses _____ prior authorization from your department head.",options:["A) require","B) requires","C) is requiring","D) required"],answer:"A",explanation:"'Require' is correct because 'all expenses' is a plural subject and takes the base form of the verb in present simple. 'Requires' is wrong because the 's' ending marks third-person singular, but 'all expenses' is plural. 'Is requiring' is wrong because 'require' is a stative verb and does not naturally take the continuous form. 'Required' is wrong because the sentence describes a current standing rule, not a past event, so simple past is inappropriate.",category:"Grammar"},
  {id:"p5m3",question:"The quarterly earnings report exceeded analyst _____ by 15 percent.",options:["A) expects","B) expectation","C) expectations","D) expected"],answer:"C",explanation:"'Expectations' is correct because 'exceed expectations' is a standard business collocation that requires the plural countable noun as the object of the verb. 'Expects' is wrong because it is a third-person singular verb and cannot function as the object of 'exceeded'. 'Expectation' is wrong because the singular form is less idiomatic here; the plural 'expectations' is the standard collocation with 'exceed'. 'Expected' is wrong because it is a past tense verb or adjective and cannot serve as the direct object of 'exceeded'.",category:"Vocabulary"},
  {id:"p5m4",question:"Employees are _____ to disclose any conflicts of interest to HR.",options:["A) obligated","B) obligating","C) obligation","D) obligate"],answer:"A",explanation:"'Obligated' is correct because 'be obligated to' is a passive construction using the past participle, meaning employees have a duty imposed on them. 'Obligating' is wrong because the present participle cannot follow 'are' in this passive construction without changing the meaning to an active progressive. 'Obligation' is wrong because it is a noun and cannot follow 'are' to form a grammatical predicate with 'to disclose'. 'Obligate' is wrong because the base form of a main verb cannot directly follow 'are' in this structure; a past participle is required.",category:"Vocabulary"},
  {id:"p5m5",question:"The software update will be _____ to all users automatically.",options:["A) rolled out","B) roll out","C) rolls out","D) rolling"],answer:"A",explanation:"'Rolled out' is correct because the sentence uses future passive voice ('will be + past participle'), and 'rolled out' is the past participle of the phrasal verb 'roll out', meaning to deploy or distribute. 'Roll out' is wrong because the base form cannot follow 'will be' to form a passive; a past participle is required. 'Rolls out' is wrong because the third-person singular present form cannot follow 'will be'. 'Rolling' is wrong because the present participle would create 'will be rolling out', an active future continuous, not a passive construction.",category:"Vocabulary"},
  {id:"p5m6",question:"_____ the economic downturn, the company maintained its profit margins.",options:["A) Although","B) Despite","C) Even though","D) While"],answer:"B",explanation:"'Despite' is correct because it is a preposition that introduces a noun phrase ('the economic downturn') to express contrast, and 'the economic downturn' is a noun phrase, not a clause. 'Although' is wrong because it is a subordinating conjunction that must be followed by a subject and verb, but 'the economic downturn' has no verb. 'Even though' is wrong for the same reason as 'although': it requires a full clause with a subject and finite verb. 'While' is wrong because it is a conjunction requiring a subject and verb, and also more commonly expresses simultaneity than contrast.",category:"Grammar"},
  {id:"p5m7",question:"The company's revenue grew _____ in the second half of the fiscal year.",options:["A) considerable","B) considerate","C) considerably","D) consideration"],answer:"C",explanation:"'Considerably' is correct because an adverb is needed to modify the verb 'grew', and 'considerably' means to a notable degree. 'Considerable' is wrong because it is an adjective and cannot modify a verb; it modifies nouns (e.g., 'a considerable increase'). 'Considerate' is wrong because it is an adjective meaning thoughtful of others, which is unrelated to the meaning required here. 'Consideration' is wrong because it is a noun and cannot function as an adverb to modify 'grew'.",category:"Vocabulary"},
  {id:"p5m8",question:"The new policy will take _____ on the first day of next month.",options:["A) effect","B) affect","C) effectiveness","D) effective"],answer:"A",explanation:"'Effect' is correct because 'take effect' is a fixed idiomatic phrase meaning to become operative or start functioning. 'Affect' is wrong because 'affect' is a verb meaning to influence, and the phrase 'take affect' does not exist. 'Effectiveness' is wrong because it is a noun meaning the quality of being effective, and 'take effectiveness' is not a recognized idiom. 'Effective' is wrong because it is an adjective and cannot fill the noun slot in the fixed phrase 'take effect'.",category:"Vocabulary"},
  {id:"p5m9",question:"It is _____ that all staff attend the mandatory safety training.",options:["A) imperative","B) imperatively","C) imperatives","D) imperativism"],answer:"A",explanation:"'Imperative' is correct because the structure 'It is + adjective + that-clause' requires an adjective after 'is', and 'imperative' means absolutely necessary. 'Imperatively' is wrong because it is an adverb and cannot function as a predicate adjective after 'is'. 'Imperatives' is wrong because it is a plural noun and would require 'these are imperatives', not 'it is imperatives'. 'Imperativism' is wrong because it is not a standard English word and has no grammatical role in this sentence.",category:"Vocabulary"},
  {id:"p5m10",question:"The board of directors has yet to _____ on the proposed acquisition.",options:["A) rule","B) decide","C) determined","D) concluding"],answer:"B",explanation:"'Decide' is correct because 'decide on' is the standard phrasal verb meaning to make a choice about something, and 'has yet to decide' means the board still hasn't made a decision. 'Rule' is wrong because 'rule on' means to give an official legal or judicial decision, which is less appropriate for a board of directors deliberating on a business acquisition. 'Determined' is wrong because 'has yet to determined' is ungrammatical; the infinitive form without 'to' would be needed, which would be 'determine'. 'Concluding' is wrong because the present participle cannot follow 'to' as an infinitive; 'to conclude' would be the correct infinitive form.",category:"Vocabulary"},
  {id:"p5m11",question:"The financial _____ suggests the company is well-positioned for growth.",options:["A) analysis","B) analyze","C) analytical","D) analyzed"],answer:"A",explanation:"'Analysis' is correct because a noun is needed after the adjective 'financial' to serve as the subject of the sentence, and 'analysis' means a detailed examination of data. 'Analyze' is wrong because it is a verb and cannot serve as a noun subject after an adjective. 'Analytical' is wrong because it is an adjective and cannot follow another adjective ('financial') as the head noun of the subject phrase. 'Analyzed' is wrong because the past tense or past participle form of a verb cannot function as a noun subject in this position.",category:"Vocabulary"},
  {id:"p5m12",question:"Workers who _____ overtime will receive additional compensation.",options:["A) work","B) works","C) are working","D) worked"],answer:"A",explanation:"'Work' is correct because in a defining relative clause, 'workers who work' uses the plural base form to agree with the plural antecedent 'workers'. 'Works' is wrong because the 's' ending signals third-person singular, but the antecedent 'workers' is plural. 'Are working' is wrong because the present continuous suggests a temporary ongoing action at this moment, whereas the relative clause describes a general condition (those who work overtime as a regular practice). 'Worked' is wrong because simple past tense implies a completed past action, but the sentence describes a general present condition that determines future compensation.",category:"Grammar"},
  {id:"p5m13",question:"The legal team reviewed the contract _____ before the signing ceremony.",options:["A) thorough","B) thoroughly","C) thoroughness","D) thoroughgoing"],answer:"B",explanation:"'Thoroughly' is correct because an adverb is needed to modify the verb 'reviewed', describing how the review was conducted. 'Thorough' is wrong because it is an adjective and cannot modify a verb; it would modify a noun (e.g., 'a thorough review'). 'Thoroughness' is wrong because it is a noun and cannot function as an adverb to modify 'reviewed'. 'Thoroughgoing' is wrong because it is a compound adjective meaning complete or absolute, and it cannot modify a verb.",category:"Grammar"},
  {id:"p5m14",question:"We ask that all visitors _____ their belongings at the front desk.",options:["A) register","B) registers","C) registered","D) registering"],answer:"A",explanation:"'Register' is correct because after 'ask that', English uses the subjunctive mood, which requires the base form of the verb regardless of the subject. 'Registers' is wrong because the third-person singular 's' ending is not used in the subjunctive mood; the base form is required. 'Registered' is wrong because the past tense is not used in the present subjunctive triggered by 'ask that'. 'Registering' is wrong because the present participle cannot replace the base form in the subjunctive construction.",category:"Grammar"},
  {id:"p5m15",question:"The new software is _____ with all existing operating systems.",options:["A) compatible","B) compatibility","C) compatibly","D) compete"],answer:"A",explanation:"'Compatible' is correct because an adjective is needed after the linking verb 'is' as a predicate adjective, and 'compatible with' is the standard collocation meaning able to work together. 'Compatibility' is wrong because it is a noun and would require a different sentence structure, such as 'The software ensures compatibility with...'. 'Compatibly' is wrong because it is an adverb and cannot serve as a predicate adjective after 'is'. 'Compete' is wrong because it is a verb meaning to rival, and 'is compete' is not grammatical.",category:"Vocabulary"},
  {id:"p5m16",question:"Sales have _____ by 30% since the product was relaunched.",options:["A) increased","B) increase","C) increasing","D) increment"],answer:"A",explanation:"'Increased' is correct because present perfect ('have + past participle') is used to describe a change that started in the past and continues to the present, especially with the time marker 'since'. 'Increase' is wrong because the base form cannot follow the auxiliary 'have'; a past participle is required. 'Increasing' is wrong because the present participle would form 'have increasing', which is ungrammatical; 'have been increasing' would be the correct continuous form. 'Increment' is wrong because it is a noun meaning a small increase and cannot function as a past participle.",category:"Grammar"},
  {id:"p5m17",question:"The project _____ unless the client approves the revised timeline.",options:["A) cannot proceed","B) can proceed","C) will proceed","D) proceeds"],answer:"A",explanation:"'Cannot proceed' is correct because the sentence expresses a negative conditional: the project is blocked and can only move forward if the client approves, so negation ('cannot') is required. 'Can proceed' is wrong because it states ability to proceed, which contradicts the restricting condition introduced by 'unless'. 'Will proceed' is wrong because it implies the project will definitely proceed, but the sentence means it will not proceed without approval. 'Proceeds' is wrong because the simple present form without a modal does not convey the conditional restriction implied by 'unless'.",category:"Grammar"},
  {id:"p5m18",question:"The HR department is _____ applications for the marketing manager position.",options:["A) accepting","B) accepted","C) acceptance","D) acceptable"],answer:"A",explanation:"'Accepting' is correct because present continuous ('is + present participle') describes an ongoing process happening during the current period, and 'accepting applications' means receiving them. 'Accepted' is wrong because it is a past participle; 'is accepted' would form a passive meaning the HR department itself is accepted by something else. 'Acceptance' is wrong because it is a noun and cannot follow 'is' as part of a verbal predicate without a different structure. 'Acceptable' is wrong because it is an adjective meaning satisfactory and would form 'is acceptable', meaning the HR department is satisfactory, which makes no sense.",category:"Grammar"},
  {id:"p5m19",question:"A comprehensive _____ of the system will be conducted next quarter.",options:["A) audit","B) auditing","C) audited","D) auditor"],answer:"A",explanation:"'Audit' is correct because a singular countable noun is needed after the article 'A' and the adjective 'comprehensive' to function as the subject, and 'audit' means an official financial or operational examination. 'Auditing' is wrong because it is a gerund or present participle; while gerunds can be subjects, 'A auditing' is unnatural and 'a comprehensive auditing' is not standard phrasing. 'Audited' is wrong because it is a past tense verb or past participle adjective and cannot serve as the head noun of the subject. 'Auditor' is wrong because it means a person who conducts audits, not the audit itself.",category:"Vocabulary"},
  {id:"p5m20",question:"The proposal was well-received by investors, _____ its innovative approach.",options:["A) due to","B) inspite","C) unless","D) wherever"],answer:"A",explanation:"'Due to' is correct because it is a prepositional phrase meaning 'because of', used to give the reason the proposal was well-received, and it correctly precedes the noun phrase 'its innovative approach'. 'Inspite' is wrong because 'in spite of' (written as three words) means despite or notwithstanding, which would create a contradiction: the proposal was well-received despite its innovative approach. 'Unless' is wrong because it is a conditional conjunction meaning 'except if', which does not logically connect the proposal's reception to its approach. 'Wherever' is wrong because it is an adverb of place meaning 'in any place that', which makes no sense in this context.",category:"Grammar"},
  {id:"p5m21",question:"The director requested that all reports _____ in by noon on Friday.",options:["A) are","B) be","C) were","D) will be"],answer:"B",explanation:"'Be' is correct because after 'requested that', the present subjunctive requires the bare infinitive (base form) regardless of the subject, making 'be' the correct form. 'Are' is wrong because the indicative present 'are' is not used in formal subjunctive constructions triggered by verbs like 'request', 'demand', or 'insist'. 'Were' is wrong because the past subjunctive 'were' is used in hypothetical or contrary-to-fact conditions (e.g., 'If I were...'), not in that-clauses after verbs of request. 'Will be' is wrong because the future form is not used in subjunctive that-clauses; the base form 'be' covers future meaning.",category:"Grammar"},
  {id:"p5m22",question:"The marketing campaign was _____ successful _____ the company decided to extend it.",options:["A) such / that","B) so / that","C) very / that","D) too / that"],answer:"B",explanation:"'So / that' is correct because 'so + adjective + that' is the standard result clause structure expressing a degree of quality that leads to a consequence. 'Such / that' is wrong because 'such...that' is used with nouns or noun phrases (e.g., 'such a success that'), not directly with bare adjectives. 'Very / that' is wrong because 'very' is an intensifier for adjectives but does not pair with 'that' to form a result clause. 'Too / that' is wrong because 'too...to' is the standard structure for excess leading to inability (e.g., 'too expensive to buy'), not for introducing a result clause with 'that'.",category:"Grammar"},
  {id:"p5m23",question:"_____ completing the online application, please attach your portfolio.",options:["A) After","B) Following","C) Upon","D) Before"],answer:"C",explanation:"'Upon' is correct because 'upon + gerund' is a formal prepositional phrase meaning 'immediately after doing something', making 'upon completing' a precise and formal instruction. 'After' is wrong because while grammatically possible with a gerund, 'after completing' lacks the sense of immediacy that 'upon' conveys in formal instructions, and the question tests the most precise formal choice. 'Following' is wrong because it is typically followed by a noun phrase, not a gerund (e.g., 'following completion of'), and 'following completing' is awkward. 'Before' is wrong because it would reverse the sequence, meaning the portfolio should be attached before the application is completed, which contradicts the intended instruction.",category:"Grammar"},
  {id:"p5m24",question:"The staff training program _____ place every quarter.",options:["A) takes","B) has","C) makes","D) does"],answer:"A",explanation:"'Takes' is correct because 'take place' is a fixed phrasal verb meaning to happen or occur, and 'takes' agrees with the singular subject 'program'. 'Has' is wrong because 'has place' is not a standard English expression; the correct expression is 'has taken place' (present perfect) if referring to completion. 'Makes' is wrong because 'make place' is not a standard idiom; the correct idiom is 'take place'. 'Does' is wrong because 'does place' is not idiomatic or grammatical in this context.",category:"Vocabulary"},
  {id:"p5m25",question:"The new CEO is known for her _____ in cost management.",options:["A) expertise","B) expert","C) expertly","D) experted"],answer:"A",explanation:"'Expertise' is correct because it is a noun meaning specialized knowledge or skill, and a noun is needed after the preposition 'for' in the phrase 'known for her expertise'. 'Expert' is wrong because it is primarily a noun meaning a person with specialist knowledge, not an abstract quality; 'her expert' would need a following noun (e.g., 'her expert opinion'). 'Expertly' is wrong because it is an adverb and cannot serve as the object of the preposition 'for'. 'Experted' is wrong because it is not a standard English word; 'expert' does not have a past tense verb form.",category:"Vocabulary"},
  {id:"p5m26",question:"The negotiations are expected to _____ in a formal agreement by next month.",options:["A) result","B) lead","C) end","D) conclude"],answer:"A",explanation:"'Result' is correct because 'result in' is the standard phrasal verb meaning to produce a specific outcome, and the preposition 'in' that follows is the key indicator. 'Lead' is wrong because while 'lead to' means to cause, the required preposition 'in' that appears in the sentence does not naturally follow 'lead'; 'lead to' would require replacing 'in' with 'to'. 'End' is wrong because 'end in' can mean to finish with a result but is less idiomatic in formal business contexts than 'result in'. 'Conclude' is wrong because 'conclude in' is not a standard collocation; 'conclude with' or simply 'conclude' is more natural.",category:"Vocabulary"},
  {id:"p5m27",question:"Her _____ dedication to customer service has earned her multiple awards.",options:["A) unwavering","B) unwave","C) unwaved","D) unwaveringly"],answer:"A",explanation:"'Unwavering' is correct because an adjective is needed to modify the noun 'dedication', and 'unwavering' means steadfast or not changing. 'Unwave' is wrong because it is not a recognized English word; the correct verb form is 'waver', but 'unwave' does not exist. 'Unwaved' is wrong because it is not a standard English word; there is no past tense 'unwaved' used as an adjective. 'Unwaveringly' is wrong because it is an adverb and cannot directly modify the noun 'dedication'; it would need to modify a verb (e.g., 'she worked unwaveringly').",category:"Vocabulary"},
  {id:"p5m28",question:"The committee will _____ the proposals and select the best one.",options:["A) evaluate","B) evaluation","C) evaluating","D) evaluated"],answer:"A",explanation:"'Evaluate' is correct because after the modal auxiliary 'will', the base form of the main verb is required. 'Evaluation' is wrong because it is a noun and cannot follow a modal auxiliary as the main verb. 'Evaluating' is wrong because the present participle cannot directly follow 'will' without the auxiliary 'be' (e.g., 'will be evaluating'). 'Evaluated' is wrong because the past participle cannot follow 'will' as an active main verb; it would require 'be' for a passive construction.",category:"Vocabulary"},
  {id:"p5m29",question:"The recent policy changes have had a _____ impact on employee morale.",options:["A) significance","B) significant","C) significantly","D) signify"],answer:"B",explanation:"'Significant' is correct because an adjective is needed to modify the noun 'impact', describing the degree of its effect. 'Significance' is wrong because it is a noun and two consecutive nouns ('significance impact') do not form a grammatical noun phrase without a preposition. 'Significantly' is wrong because it is an adverb and cannot modify a noun directly; it would modify a verb or adjective. 'Signify' is wrong because it is a verb meaning to indicate and cannot serve as a modifier for the noun 'impact'.",category:"Word Form"},
  {id:"p5m30",question:"The company has been _____ expanding its product portfolio over the past year.",options:["A) active","B) actively","C) activation","D) activated"],answer:"B",explanation:"'Actively' is correct because an adverb is needed to modify the present participle 'expanding', indicating the manner in which the company is expanding. 'Active' is wrong because it is an adjective and cannot directly modify a verb or participle; it would modify a noun. 'Activation' is wrong because it is a noun meaning the process of making something active and cannot function as an adverb modifier. 'Activated' is wrong because it is a past tense verb or past participle adjective and cannot modify the gerund/participle 'expanding'.",category:"Word Form"},
  {id:"p5m31",question:"Neither the revised proposal nor the original plan _____ approved by the board.",options:["A) was","B) were","C) have","D) are"],answer:"A",explanation:"'Was' is correct because with the correlative conjunction 'neither...nor', the verb agrees with the noun closest to it, which is 'plan' (singular), so the singular past tense 'was' is required. 'Were' is wrong because while 'were' agrees with plural subjects, the proximity rule for 'neither...nor' dictates agreement with the nearest noun 'plan', which is singular. 'Have' is wrong because it is a plural present auxiliary and does not agree with the singular nearest noun 'plan', nor is a present perfect appropriate given the context. 'Are' is wrong because it is a plural present tense verb, but the nearest noun is singular and the context calls for a past tense form.",category:"Grammar"},
  {id:"p5m32",question:"_____ the meeting ended, the team immediately began working on the action plan.",options:["A) As soon as","B) By the time","C) Until","D) When"],answer:"A",explanation:"'As soon as' is correct because it emphasizes that the team began working immediately after the meeting ended, and 'immediately' in the main clause confirms this sense of urgency and rapid sequence. 'By the time' is wrong because 'by the time the meeting ended' implies the other action was already completed before the meeting ended, which contradicts the sentence. 'Until' is wrong because 'until the meeting ended' would mean the team worked only up to the point when the meeting ended, which reverses the intended meaning. 'When' is wrong because while grammatically possible, it does not carry the same sense of immediacy as 'as soon as', which is the most precise choice here.",category:"Grammar"},
  {id:"p5m33",question:"The position requires someone who _____ manage multiple projects simultaneously.",options:["A) can","B) could have","C) should have","D) might have"],answer:"A",explanation:"'Can' is correct because the sentence describes a current ability required for the job, and 'can' expresses present capability. 'Could have' is wrong because 'could have + past participle' expresses an unrealized ability in the past, not a current job requirement. 'Should have' is wrong because 'should have + past participle' expresses a past obligation that was not fulfilled, which is irrelevant to describing a job requirement. 'Might have' is wrong because 'might have + past participle' expresses possibility about a past event, not a present ability requirement.",category:"Modal"},
  {id:"p5m34",question:"The prototype _____ further testing before it can be approved for production.",options:["A) undergoes","B) will undergo","C) underwent","D) undergoing"],answer:"B",explanation:"'Will undergo' is correct because the sentence describes a future planned process that has not yet occurred, and 'will + base form' expresses a simple future action. 'Undergoes' is wrong because the present simple implies the testing is already happening as a regular routine, but the context indicates this is a future requirement before approval. 'Underwent' is wrong because the simple past indicates the testing has already been completed, which contradicts 'before it can be approved', implying approval has not yet happened. 'Undergoing' is wrong because the present participle alone cannot serve as the main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m35",question:"All team members are expected to _____ the project management software.",options:["A) proficient in","B) be proficient in","C) proficiency in","D) proficiently"],answer:"B",explanation:"'Be proficient in' is correct because 'expected to' must be followed by an infinitive, and 'be proficient in' is the full infinitive phrase, with 'proficient' as an adjective following the linking verb 'be'. 'Proficient in' is wrong because it omits the required infinitive 'be'; 'expected to proficient' is not grammatical. 'Proficiency in' is wrong because it is a noun phrase and cannot follow 'expected to' without the verb 'be' (e.g., 'expected to demonstrate proficiency in'). 'Proficiently' is wrong because an adverb cannot directly follow 'expected to'; a verb or adjective phrase is required.",category:"Vocabulary"},
  {id:"p5m36",question:"The sales target _____ been revised upward following the strong Q1 results.",options:["A) was","B) has","C) have","D) is"],answer:"B",explanation:"'Has' is correct because the sentence describes a recent action with present relevance (the target was just revised), which calls for the present perfect, and 'has' is the singular auxiliary agreeing with the singular subject 'sales target'. 'Was' is wrong because 'was been revised' is not grammatical; 'was revised' (simple passive past) would be correct, but 'was' cannot precede 'been'. 'Have' is wrong because it is the plural auxiliary and does not agree with the singular subject 'sales target'. 'Is' is wrong because 'is been revised' is not a standard grammatical construction; 'is being revised' would mean the revision is currently in progress.",category:"Grammar"},
  {id:"p5m37",question:"The supplier offered a 10% discount _____ we place an order of 500 units.",options:["A) provided","B) provide","C) providing","D) unless"],answer:"A",explanation:"'Provided' is correct because 'provided that' is a conditional conjunction meaning 'on the condition that', introducing the requirement for the discount to apply. 'Provide' is wrong because the bare base form 'provide' cannot function as a conjunction to introduce a conditional clause in this position. 'Providing' is wrong because while 'providing that' can sometimes be used as an informal conditional, 'provided that' is the more standard and formal choice, and 'providing we place' without 'that' is less idiomatic. 'Unless' is wrong because it means 'except if', implying the discount would be given in all cases except when an order is placed, which reverses the intended meaning.",category:"Grammar"},
  {id:"p5m38",question:"Employees _____ to check in with their manager before taking unscheduled leave.",options:["A) are expected","B) expect","C) expecting","D) have expected"],answer:"A",explanation:"'Are expected' is correct because this is a passive construction expressing an organizational requirement placed on employees from an external authority, meaning the expectation comes from management or policy. 'Expect' is wrong because the active voice 'employees expect' implies that employees themselves have the expectation, which reverses the intended meaning. 'Expecting' is wrong because the present participle alone cannot serve as the finite main verb of the sentence. 'Have expected' is wrong because the present perfect active 'have expected' implies employees themselves anticipated something in the past, not that a rule is placed on them.",category:"Grammar"},
  {id:"p5m39",question:"The renovation is _____ to be completed in early March.",options:["A) schedule","B) scheduled","C) scheduling","D) schedules"],answer:"B",explanation:"'Scheduled' is correct because 'is scheduled to' is a passive construction using the past participle, indicating that a plan has been made (by someone in authority) for the renovation to be completed. 'Schedule' is wrong because the base form of a verb cannot follow 'is' to form a predicate in this way; a past participle is needed for the passive. 'Scheduling' is wrong because 'is scheduling to' is not grammatical; the correct progressive would be 'is scheduling the renovation', meaning the subject is actively creating a schedule. 'Schedules' is wrong because the third-person singular present tense cannot follow 'is' as a main verb predicate.",category:"Grammar"},
  {id:"p5m40",question:"The company announced a _____ restructuring plan to improve operational efficiency.",options:["A) major","B) majority","C) majorly","D) majored"],answer:"A",explanation:"'Major' is correct because an adjective is needed between the article 'a' and the noun 'restructuring plan' to describe its scale, and 'major' means of great importance or extent. 'Majority' is wrong because it is a noun meaning more than half, and placing a noun before another noun here would create a compound where 'majority' modifies 'restructuring plan' unnaturally. 'Majorly' is wrong because it is an adverb and cannot modify a noun; it would modify a verb or adjective. 'Majored' is wrong because it is the past tense of the verb 'major' (as in 'she majored in economics') and cannot function as an adjective.",category:"Word Form"},
  {id:"p5m41",question:"The team leader suggested _____ the client directly to clarify expectations.",options:["A) contact","B) contacting","C) contacted","D) to contact"],answer:"B",explanation:"'Contacting' is correct because 'suggest' is a verb that takes a gerund (verb + -ing) as its object, not an infinitive; the rule is that verbs like suggest, recommend, and avoid are followed by gerunds. 'Contact' is wrong because the bare base form cannot directly follow 'suggested' as an object; 'suggest contact' would require a noun like 'direct contact'. 'Contacted' is wrong because the past tense form cannot function as the gerund object of 'suggested'. 'To contact' is wrong because 'suggest' does not take an infinitive; 'suggest to contact' is a common error, but the correct form is the gerund 'contacting'.",category:"Grammar"},
  {id:"p5m42",question:"We need to _____ our resources more efficiently to stay within budget.",options:["A) allocate","B) allocation","C) allocated","D) allocating"],answer:"A",explanation:"'Allocate' is correct because after 'need to', the base form (bare infinitive) of the main verb is required. 'Allocation' is wrong because it is a noun and cannot follow 'to' as part of an infinitive; it would need a different structure (e.g., 'better allocation of resources'). 'Allocated' is wrong because the past tense or past participle form cannot follow 'to' in an infinitive construction. 'Allocating' is wrong because the gerund or present participle cannot directly follow 'to' in an infinitive; 'need allocating' would require a different structure.",category:"Vocabulary"},
  {id:"p5m43",question:"The CEO's decision was _____ by the majority of the shareholders.",options:["A) back","B) backed","C) backing","D) backs"],answer:"B",explanation:"'Backed' is correct because the sentence uses passive voice ('was + past participle'), and 'backed by' means supported by. 'Back' is wrong because the base form cannot follow 'was' to form a passive; a past participle is required. 'Backing' is wrong because the present participle would form 'was backing', creating a past progressive active meaning (the decision was backing something), not a passive meaning. 'Backs' is wrong because the third-person singular present tense cannot follow 'was' grammatically.",category:"Grammar"},
  {id:"p5m44",question:"Due to unforeseen circumstances, the product launch has been _____ indefinitely.",options:["A) delayed","B) delay","C) delaying","D) delays"],answer:"A",explanation:"'Delayed' is correct because the present perfect passive ('has been + past participle') indicates that someone has postponed the launch, and 'delayed indefinitely' means it is postponed without a set new date. 'Delay' is wrong because the base form cannot follow 'has been' to form a passive perfect; a past participle is required. 'Delaying' is wrong because 'has been delaying' would be present perfect progressive active, meaning the launch has been postponing something else, which makes no sense. 'Delays' is wrong because the third-person singular present form cannot follow 'has been'.",category:"Grammar"},
  {id:"p5m45",question:"The company's _____ to sustainability has been praised by environmental groups.",options:["A) commit","B) committed","C) commitment","D) committing"],answer:"C",explanation:"'Commitment' is correct because a noun is needed after the possessive 'the company's' to serve as the subject of the sentence, and 'commitment to' means a dedication or pledge to a cause. 'Commit' is wrong because it is the base form of a verb and cannot follow the possessive 'company's' as a noun subject. 'Committed' is wrong because while 'committed' can be an adjective, 'the company's committed to sustainability' is ungrammatical as a noun phrase; you would say 'the company is committed to'. 'Committing' is wrong because the gerund 'committing' after a possessive ('the company's committing') sounds awkward and non-idiomatic compared to the standard noun 'commitment'.",category:"Word Form"},
  {id:"p5m46",question:"We _____ the contract only after receiving the signed NDA from both parties.",options:["A) signed","B) will sign","C) sign","D) would sign"],answer:"B",explanation:"'Will sign' is correct because the sentence describes a future action that will happen after a condition is met, and 'will + base form' expresses a definite future intention. 'Signed' is wrong because simple past implies the signing already happened, but the condition ('after receiving the signed NDA') suggests it has not yet occurred. 'Sign' is wrong because the simple present does not convey the future intent; 'only after receiving' suggests the signing is planned for the future. 'Would sign' is wrong because 'would' is used for hypothetical or conditional situations (e.g., 'We would sign if we received...'), but the sentence presents a factual future condition, not a hypothetical one.",category:"Grammar"},
  {id:"p5m47",question:"The analyst's report highlighted several _____ trends in the consumer market.",options:["A) emerge","B) emerged","C) emerging","D) emergence"],answer:"C",explanation:"'Emerging' is correct because the present participle 'emerging' functions as an adjective modifying 'trends', describing trends that are currently developing or coming into view. 'Emerge' is wrong because the base form of a verb cannot directly modify a noun as an adjective; it would need to be in a relative clause ('trends that emerge'). 'Emerged' is wrong because 'emerged trends' would imply the trends have fully appeared in the past, whereas 'emerging trends' describes trends that are in the process of developing. 'Emergence' is wrong because it is a noun meaning the process of coming into being, and it cannot directly modify another noun in this context.",category:"Word Form"},
  {id:"p5m48",question:"The board was _____ by the team's ability to deliver results under pressure.",options:["A) impress","B) impressive","C) impressed","D) impressing"],answer:"C",explanation:"'Impressed' is correct because 'be impressed by' is a passive adjectival construction expressing a state of being affected positively, and the past participle 'impressed' follows the linking verb 'was'. 'Impress' is wrong because the base form cannot follow 'was' to form a passive or predicate; a past participle is needed. 'Impressive' is wrong because while it is an adjective, 'was impressive' would mean the board itself was impressive, not that the board felt impressed; 'impressed' indicates the board's feeling. 'Impressing' is wrong because 'was impressing' is the past progressive active, meaning the board was in the process of impressing someone else.",category:"Grammar"},
  {id:"p5m49",question:"The company's overseas expansion is _____ to regulatory approval in each market.",options:["A) subject","B) subjected","C) subjects","D) subjecting"],answer:"A",explanation:"'Subject' is correct because 'subject to' is a fixed prepositional expression meaning conditional upon or dependent on, and in this structure 'subject' is used as a predicate adjective after 'is'. 'Subjected' is wrong because 'subjected to' implies being forced to undergo something unpleasant (e.g., 'subjected to scrutiny'), which carries a different meaning and does not fit as naturally here. 'Subjects' is wrong because the third-person singular present tense form would require 'subjects' to be the main verb of a new clause, which does not grammatically fit after 'is'. 'Subjecting' is wrong because 'is subjecting to' would mean the expansion is actively subjecting something else, which reverses the meaning.",category:"Vocabulary"},
  {id:"p5m50",question:"The IT department is _____ a new cybersecurity protocol for all users.",options:["A) implement","B) implemented","C) implementing","D) implementation"],answer:"C",explanation:"'Implementing' is correct because present continuous ('is + present participle') describes an action currently in progress, and 'implementing a protocol' means the department is actively deploying it. 'Implement' is wrong because the base form cannot follow 'is' to form a continuous tense; 'is implement' is not grammatical. 'Implemented' is wrong because 'is implemented' would form a passive meaning the protocol is being implemented by someone, making the IT department the subject of an odd passive. 'Implementation' is wrong because it is a noun and cannot follow 'is' as part of a verb phrase without restructuring.",category:"Grammar"},
  {id:"p5m51",question:"Staff who wish to apply for the transfer _____ submit their request by Friday.",options:["A) need","B) needs","C) needing","D) needed"],answer:"A",explanation:"'Need' is correct because the subject 'staff who wish to apply' is a plural noun phrase (staff is treated as plural here), so the base form 'need' without a third-person singular 's' is required. 'Needs' is wrong because 'needs' is third-person singular, but the subject 'staff...who wish' is a plural collective referring to multiple individuals. 'Needing' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary. 'Needed' is wrong because the simple past implies the deadline has passed, but the sentence is giving a current instruction.",category:"Grammar"},
  {id:"p5m52",question:"The new employee onboarding program is designed to _____ new hires integrate quickly.",options:["A) help","B) helping","C) helped","D) helps"],answer:"A",explanation:"'Help' is correct because 'designed to help' requires the base infinitive after 'to', and 'help + object + base infinitive' is the standard causative structure meaning to assist someone in doing something. 'Helping' is wrong because the gerund or present participle cannot follow 'to' in an infinitive construction; 'designed to helping' is not grammatical. 'Helped' is wrong because the past tense form cannot follow 'to' as an infinitive. 'Helps' is wrong because the third-person singular present form cannot follow 'to' in an infinitive; 'to helps' is not grammatical.",category:"Grammar"},
  {id:"p5m53",question:"The latest version of the software has addressed the _____ reported by users.",options:["A) issues","B) issue","C) issuing","D) issued"],answer:"A",explanation:"'Issues' is correct because the plural noun 'issues' is modified by the past participle 'reported by users', meaning the multiple problems that users flagged, and plural is natural when referring to a variety of user complaints. 'Issue' is wrong because the singular would imply there is only one specific problem, whereas 'the issues reported by users' more naturally covers a range of complaints. 'Issuing' is wrong because 'the issuing reported by users' is not grammatical; 'issuing' is a present participle that would need to modify something else. 'Issued' is wrong because 'the issued reported' is not natural; 'issued' as a past participle adjective modifying a noun would give 'issued notices', not 'issued reported'.",category:"Grammar"},
  {id:"p5m54",question:"Management has _____ a plan to gradually phase out the legacy system.",options:["A) devised","B) devise","C) devising","D) devises"],answer:"A",explanation:"'Devised' is correct because 'has devised' is present perfect active, meaning management has recently created a plan, and the past participle 'devised' is required after 'has'. 'Devise' is wrong because the base form cannot follow 'has' in the present perfect; a past participle is required. 'Devising' is wrong because 'has devising' is not grammatical; 'has been devising' would be the present perfect progressive form. 'Devises' is wrong because the third-person singular present form cannot follow 'has' in a perfect construction.",category:"Vocabulary"},
  {id:"p5m55",question:"The contract is _____ only if both parties sign the amendment.",options:["A) valid","B) validity","C) validate","D) validating"],answer:"A",explanation:"'Valid' is correct because a predicate adjective is needed after the linking verb 'is', and 'valid' means legally or officially acceptable. 'Validity' is wrong because it is a noun meaning the quality of being valid; 'is validity' would require a different structure, such as 'the validity of the contract depends on...'. 'Validate' is wrong because it is a verb meaning to make valid, and 'is validate' is not grammatical as a predicate. 'Validating' is wrong because 'is validating' is the present continuous active, meaning the contract is in the process of validating something else, which makes no sense.",category:"Vocabulary"},
  {id:"p5m56",question:"The department head is _____ for approving all budget expenditures over $1,000.",options:["A) accountable","B) accountability","C) account","D) accounting"],answer:"A",explanation:"'Accountable' is correct because 'accountable for' is a standard adjective phrase meaning responsible for justifying or answering for specific actions, and an adjective is required after the linking verb 'is'. 'Accountability' is wrong because it is a noun; 'is accountability' would be grammatically incorrect as a predicate without restructuring. 'Account' is wrong because as a noun, 'is account' is not grammatical, and as a verb, 'accounts for' means to explain or constitute, not to be responsible for approving. 'Accounting' is wrong because 'is accounting for' means actively providing an explanation for something, not holding responsibility.",category:"Vocabulary"},
  {id:"p5m57",question:"New product launches are always _____ a thorough quality assurance review.",options:["A) preceded by","B) precede","C) preceding","D) precedes"],answer:"A",explanation:"'Preceded by' is correct because the sentence is in passive voice, meaning the launches always have a review come before them, and 'be preceded by' is the passive form of 'precede'. 'Precede' is wrong because the active base form 'precede' would require the subject to be the thing that comes first, but here 'launches' are preceded by something else, requiring passive voice. 'Preceding' is wrong because 'are preceding' would be an active present progressive meaning the launches are currently going before something, which reverses the meaning. 'Precedes' is wrong because the third-person singular active form cannot follow 'are' to form a passive.",category:"Grammar"},
  {id:"p5m58",question:"The team was able to meet the deadline _____ the unexpected technical challenges.",options:["A) despite","B) although","C) because","D) whereas"],answer:"A",explanation:"'Despite' is correct because it is a preposition meaning notwithstanding, followed here by a noun phrase ('the unexpected technical challenges'), expressing contrast between the challenges and the team's success. 'Although' is wrong because it is a subordinating conjunction requiring a full clause (subject + verb), but 'the unexpected technical challenges' is a noun phrase without a verb. 'Because' is wrong because it introduces a reason or cause, meaning the challenges helped them meet the deadline, which contradicts the intended meaning of overcoming adversity. 'Whereas' is wrong because it is a conjunction introducing a contrasting clause with a subject and verb, but the phrase following the blank is a noun phrase.",category:"Grammar"},
  {id:"p5m59",question:"_____ profits were strong last quarter, expenses also rose significantly.",options:["A) Although","B) Despite","C) However","D) Due to"],answer:"A",explanation:"'Although' is correct because it is a subordinating conjunction that introduces a concessive clause ('profits were strong last quarter') with a full subject and verb, expressing contrast with the main clause. 'Despite' is wrong because it is a preposition and must be followed by a noun phrase or gerund, not a full clause with subject and verb. 'However' is wrong because it is a conjunctive adverb used to contrast two separate sentences or independent clauses; it cannot introduce a subordinate clause. 'Due to' is wrong because it is a prepositional phrase expressing reason or cause, not contrast, and it requires a noun phrase, not a clause.",category:"Grammar"},
  {id:"p5m60",question:"She handled the client's complaint with remarkable _____ and professionalism.",options:["A) patient","B) patience","C) patiently","D) patients"],answer:"B",explanation:"'Patience' is correct because a noun is needed after the adjective 'remarkable' and the preposition 'with' to form a noun phrase, and 'patience' is the abstract noun meaning calm endurance. 'Patient' is wrong because it is an adjective meaning able to wait calmly, or a noun referring to a person receiving medical care; neither meaning fits after 'remarkable' as an abstract quality. 'Patiently' is wrong because it is an adverb and cannot serve as the object of the preposition 'with'. 'Patients' is wrong because it is the plural noun referring to medical patients, which is entirely unrelated to the professional context of handling a complaint.",category:"Word Form"},
  {id:"p5m61",question:"The company _____ considerable losses if the lawsuit is not settled.",options:["A) incurs","B) will incur","C) incurred","D) incurring"],answer:"B",explanation:"'Will incur' is correct because the sentence describes a future consequence dependent on a conditional ('if the lawsuit is not settled'), and 'will + base form' expresses a predicted future outcome. 'Incurs' is wrong because the simple present implies the company is currently incurring losses as a routine matter, not as a future conditional consequence. 'Incurred' is wrong because simple past indicates the losses have already been sustained in the past, but the sentence refers to a future possibility. 'Incurring' is wrong because the present participle alone cannot serve as the finite main verb of the sentence.",category:"Grammar"},
  {id:"p5m62",question:"The vendor provided _____ with a comprehensive maintenance package.",options:["A) us","B) our","C) we","D) ours"],answer:"A",explanation:"'Us' is correct because an object pronoun is required as the indirect object of the verb 'provided', and 'us' is the first-person plural object form. 'Our' is wrong because it is a possessive adjective (determiner) that must precede a noun, not function independently as an object. 'We' is wrong because it is a subject pronoun and cannot serve as the object of a verb. 'Ours' is wrong because it is a possessive pronoun used when replacing a noun ('that report is ours'), not as an indirect object of a verb.",category:"Grammar"},
  {id:"p5m63",question:"All vehicles _____ in the designated areas must display a valid permit.",options:["A) park","B) parking","C) parked","D) to park"],answer:"C",explanation:"'Parked' is correct because the past participle 'parked' functions as a reduced relative clause ('vehicles that are parked'), acting as a post-nominal adjective modifying 'vehicles'. 'Park' is wrong because the base verb form cannot directly modify a noun as a post-nominal modifier without a relative pronoun and auxiliary. 'Parking' is wrong because the present participle 'parking' would describe vehicles currently in the act of parking (moving into a spot), not stationary vehicles already parked. 'To park' is wrong because the infinitive 'to park' in this position would express purpose (vehicles intended for parking) rather than describing their location.",category:"Grammar"},
  {id:"p5m64",question:"The department's budget was _____ reduced to accommodate company-wide cost cuts.",options:["A) drastic","B) drastically","C) drasticness","D) drasted"],answer:"B",explanation:"'Drastically' is correct because an adverb is needed to modify the past participle 'reduced', describing the degree or extent of the reduction. 'Drastic' is wrong because it is an adjective and cannot modify a past participle or verb; it would modify a noun (e.g., 'a drastic reduction'). 'Drasticness' is wrong because while it might theoretically exist as a noun, it is not a standard English word in common use and cannot function as an adverb. 'Drasted' is wrong because it is not a real English word; 'drastic' does not have a verb or past tense form.",category:"Word Form"},
  {id:"p5m65",question:"The new hire will receive _____ training during her first two weeks.",options:["A) intensive","B) intensity","C) intensively","D) intensify"],answer:"A",explanation:"'Intensive' is correct because an adjective is needed to modify the noun 'training', describing the nature of the training, and 'intensive' means concentrated and thorough. 'Intensity' is wrong because it is a noun meaning the degree of strength or force, and a noun cannot directly modify another noun in this context without sounding like a compound noun, which 'intensity training' is not. 'Intensively' is wrong because it is an adverb and cannot modify a noun; it would modify a verb (e.g., 'she trained intensively'). 'Intensify' is wrong because it is a verb meaning to make stronger, and it cannot function as a modifier for a noun.",category:"Word Form"},
  {id:"p5m66",question:"The _____ of the deal depends on completing the environmental assessment.",options:["A) finalize","B) finalized","C) finalization","D) finally"],answer:"C",explanation:"'Finalization' is correct because the sentence requires a noun as the subject of the verb 'depends', and 'finalization' is the noun form meaning the process of making something final. 'Finalize' is wrong because it is a verb meaning to complete arrangements and cannot serve as the subject noun of the sentence. 'Finalized' is wrong because it is a past tense verb or past participle adjective and cannot be the noun subject of 'depends'. 'Finally' is wrong because it is an adverb meaning at last or in the end, and it cannot function as a noun subject.",category:"Word Form"},
  {id:"p5m67",question:"She was _____ appointed to lead the cross-functional project team.",options:["A) recent","B) recently","C) recentness","D) recency"],answer:"B",explanation:"'Recently' is correct because an adverb is needed to modify the past participle 'appointed', indicating when the appointment took place. 'Recent' is wrong because it is an adjective and cannot modify a past participle; it would modify a noun (e.g., 'a recent appointment'). 'Recentness' is wrong because while it is technically a noun, it is rarely used in standard English and cannot function as an adverb modifier. 'Recency' is wrong because it is a noun meaning the quality of being recent and cannot function as an adverb to modify a verb or participle.",category:"Word Form"},
  {id:"p5m68",question:"We are committed to _____ transparent communication with all stakeholders.",options:["A) maintain","B) maintaining","C) maintained","D) maintenance"],answer:"B",explanation:"'Maintaining' is correct because 'committed to' is a fixed expression where 'to' is a preposition (not part of an infinitive), and prepositions must be followed by a noun or gerund, making 'maintaining' the correct gerund form. 'Maintain' is wrong because the bare infinitive follows 'to' in infinitive constructions, but 'committed to' uses 'to' as a preposition requiring a gerund. 'Maintained' is wrong because the past tense or past participle form cannot serve as the object of a preposition. 'Maintenance' is wrong because the noun 'maintenance' omits the object 'transparent communication'; while 'committed to maintenance' is grammatical, 'committed to maintaining transparent communication' better preserves the intended meaning.",category:"Grammar"},
  {id:"p5m69",question:"The quarterly results showed a _____ improvement over the previous period.",options:["A) remark","B) remarked","C) remarkable","D) remarkably"],answer:"C",explanation:"'Remarkable' is correct because an adjective is needed between the article 'a' and the noun 'improvement' to describe the quality of the improvement, and 'remarkable' means extraordinarily good or worthy of attention. 'Remark' is wrong because it is a noun (a comment) or verb and cannot directly modify the noun 'improvement'. 'Remarked' is wrong because it is the past tense of the verb 'remark' and cannot serve as an adjective before a noun. 'Remarkably' is wrong because it is an adverb and cannot modify a noun; it would modify an adjective (e.g., 'a remarkably strong improvement').",category:"Word Form"},
  {id:"p5m70",question:"The product is _____ for its durability and ease of use.",options:["A) knew","B) known","C) knowing","D) know"],answer:"B",explanation:"'Known' is correct because 'be known for' is a passive adjectival construction where the past participle 'known' follows the linking verb 'is', describing the product's reputation. 'Knew' is wrong because it is the simple past tense of 'know' and cannot follow 'is' to form a passive or predicate adjective. 'Knowing' is wrong because 'is knowing' is the present continuous active, meaning the product is currently knowing something, which makes no sense for an inanimate object. 'Know' is wrong because the base form cannot follow 'is' to form a predicate in standard English grammar.",category:"Vocabulary"},
  {id:"p5m71",question:"As part of the restructuring, three departments will be _____ into one.",options:["A) merged","B) merge","C) merging","D) merges"],answer:"A",explanation:"'Merged' is correct because the sentence uses future passive voice ('will be + past participle'), and 'merged into one' describes the planned consolidation of departments. 'Merge' is wrong because the base form cannot follow 'will be' to form a passive; a past participle is required. 'Merging' is wrong because 'will be merging' is the future progressive active, meaning the departments themselves are actively merging something, not being merged by an external process. 'Merges' is wrong because the third-person singular present cannot follow 'will be'.",category:"Grammar"},
  {id:"p5m72",question:"Management _____ that all employees adhere to the new code of conduct.",options:["A) insists","B) insist","C) insisted","D) insisting"],answer:"A",explanation:"'Insists' is correct because 'management' is treated as a singular collective noun in this context, requiring the third-person singular 's' form in the present simple to describe its ongoing organizational stance. 'Insist' is wrong because the base form is used with plural subjects, but 'management' as a collective singular requires 'insists'. 'Insisted' is wrong because simple past implies this was a past stance no longer in effect, but the present simple 'insists' indicates an ongoing, current requirement. 'Insisting' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m73",question:"The firm has _____ significant resources into developing the new platform.",options:["A) invested","B) invest","C) investing","D) investment"],answer:"A",explanation:"'Invested' is correct because 'has invested' is the present perfect active, indicating the firm has put resources in (with the result that the platform is being developed), and the past participle 'invested' is required after 'has'. 'Invest' is wrong because the base form cannot follow 'has'; a past participle is needed for the present perfect. 'Investing' is wrong because 'has investing' is not grammatical; 'has been investing' would be the present perfect progressive form. 'Investment' is wrong because it is a noun and cannot follow 'has' as a past participle.",category:"Grammar"},
  {id:"p5m74",question:"The client requested _____ changes to the original design.",options:["A) several","B) much","C) a few","D) few of"],answer:"A",explanation:"'Several' is correct because 'changes' is a countable plural noun, and 'several' is a determiner used with countable plurals to mean more than two but not a large number. 'Much' is wrong because 'much' is used with uncountable nouns (e.g., 'much time'), not with countable plurals like 'changes'. 'A few' is wrong because while grammatically possible with a countable plural, 'a few changes' implies only a small number, whereas 'several' better suggests a more notable quantity of requested changes. 'Few of' is wrong because 'few of changes' is not grammatical; 'few of the changes' would require a definite article, and in this context it would mean 'not many of the changes were requested', which reverses the meaning.",category:"Grammar"},
  {id:"p5m75",question:"The agreement _____ both parties to maintain confidentiality for five years.",options:["A) obligates","B) obligate","C) obligating","D) obligation"],answer:"A",explanation:"'Obligates' is correct because the subject 'the agreement' is singular and requires the third-person singular 's' form of the verb in the present simple tense. 'Obligate' is wrong because the base form without 's' is used with plural subjects or in modal constructions, not with a singular subject like 'the agreement'. 'Obligating' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary. 'Obligation' is wrong because it is a noun and cannot function as the main verb of the sentence.",category:"Grammar"},
  {id:"p5m76",question:"All conference registrations must be _____ at least three weeks in advance.",options:["A) complete","B) completed","C) completing","D) completion"],answer:"B",explanation:"'Completed' is correct because the sentence uses a passive modal construction ('must be + past participle'), meaning someone must complete the registrations, and 'completed' is the required past participle. 'Complete' is wrong because the adjective or base verb form cannot follow 'must be' to form a passive; a past participle is needed. 'Completing' is wrong because 'must be completing' is a modal progressive, suggesting the registrations are expected to be in the process of completing themselves, which is awkward. 'Completion' is wrong because it is a noun and cannot follow 'must be' as part of a passive verb phrase.",category:"Grammar"},
  {id:"p5m77",question:"The consultant _____ the team with strategies for entering the new market.",options:["A) provides","B) provided","C) was providing","D) has provide"],answer:"B",explanation:"'Provided' is correct because simple past tense is used to describe a completed consulting engagement, indicating the consultant's work with the team is finished. 'Provides' is wrong because the simple present suggests this is an ongoing or habitual action, but the context implies a specific completed engagement. 'Was providing' is wrong because the past progressive suggests the action was interrupted or ongoing at a specific past moment, which is not implied by the sentence. 'Has provide' is wrong because the present perfect requires the past participle 'provided', not the base form 'provide'; 'has provided' would be the correct present perfect form.",category:"Grammar"},
  {id:"p5m78",question:"Each candidate will have _____ to complete the written test.",options:["A) an hour","B) one hour of","C) one-hour","D) for an hour"],answer:"A",explanation:"'An hour' is correct because 'will have an hour' is the standard idiomatic expression for being given a duration of time, where 'an hour' is a noun phrase functioning as the object of 'have'. 'One hour of' is wrong because adding 'of' requires a following noun (e.g., 'one hour of time'), and 'one hour of to complete' is not grammatical. 'One-hour' is wrong because it is a compound adjective (used before a noun, e.g., 'a one-hour test') and cannot function as the object of 'will have'. 'For an hour' is wrong because the prepositional phrase 'for an hour' cannot serve as the object of 'will have' in this structure.",category:"Grammar"},
  {id:"p5m79",question:"The company's profitability is closely _____ with customer retention rates.",options:["A) link","B) linking","C) linked","D) linkage"],answer:"C",explanation:"'Linked' is correct because 'is linked with' is a passive adjectival construction indicating a strong correlation, and the past participle 'linked' follows the adverb 'closely' and the linking verb 'is'. 'Link' is wrong because the base verb form cannot follow an adverb and 'is' to form a passive predicate. 'Linking' is wrong because 'is linking' is the present continuous active, meaning profitability is currently connecting something to customer retention rates, which reverses the meaning. 'Linkage' is wrong because it is a noun meaning a connection and cannot follow the adverb 'closely' and 'is' as part of a verb phrase.",category:"Grammar"},
  {id:"p5m80",question:"The keynote speaker _____ over 20 years of experience in the technology industry.",options:["A) bringing","B) brought","C) brings","D) bring"],answer:"C",explanation:"'Brings' is correct because the present simple describes a current fact about the speaker — the experience the speaker brings to this event now — and the third-person singular 's' agrees with the singular subject 'keynote speaker'. 'Bringing' is wrong because the present participle cannot serve as the finite main verb without an auxiliary (e.g., 'is bringing'). 'Brought' is wrong because the simple past implies the speaker contributed this experience in the past but no longer does, which is not the intended meaning. 'Bring' is wrong because the base form without 's' does not agree with the third-person singular subject 'the keynote speaker'.",category:"Grammar"},
  {id:"p5m81",question:"The proposal was sent to the client for _____ last Thursday.",options:["A) review","B) reviewing","C) reviewed","D) reviews"],answer:"A",explanation:"'Review' is correct because after the preposition 'for', a bare noun is used in fixed purpose phrases like 'for review', 'for approval', and 'for consideration', indicating the purpose of sending. 'Reviewing' is wrong because while gerunds can follow prepositions, 'for reviewing' would imply the client is reviewing it now, whereas 'for review' is the idiomatic phrase indicating it was sent for the purpose of being reviewed. 'Reviewed' is wrong because the past tense or past participle cannot function as the object of the preposition 'for' in this fixed phrase. 'Reviews' is wrong because the plural noun 'reviews' would imply the proposal was sent to produce multiple reviews, which changes the meaning.",category:"Word Form"},
  {id:"p5m82",question:"_____ the final figures, the company performed well above market expectations.",options:["A) Based on","B) In based on","C) Basing","D) Due"],answer:"A",explanation:"'Based on' is correct because it is a fixed prepositional phrase used as a discourse marker meaning 'using as a foundation', introducing the evidence for the claim in the main clause. 'In based on' is wrong because 'in' is redundant before 'based on'; the phrase is simply 'based on', not 'in based on'. 'Basing' is wrong because 'basing the final figures, the company performed...' would create a dangling modifier implying the company is basing the figures, not using them to evaluate performance. 'Due' is wrong because 'due' alone is not a preposition; 'due to' is the correct prepositional phrase meaning because of, but here the meaning is 'based on', not causal.",category:"Grammar"},
  {id:"p5m83",question:"The committee found the project _____ and approved it unanimously.",options:["A) merit","B) merited","C) meritorious","D) meritoriously"],answer:"C",explanation:"'Meritorious' is correct because after 'found the project', an adjective is needed as an object complement describing the committee's assessment of the project, and 'meritorious' means deserving reward or praise. 'Merit' is wrong because it is a noun or verb; 'found the project merit' is not idiomatic as an object complement structure. 'Merited' is wrong because 'found the project merited' would mean 'found that the project merited (something)', requiring an object after 'merited', and does not function as a simple adjective complement. 'Meritoriously' is wrong because it is an adverb and cannot serve as an object complement adjective after 'found the project'.",category:"Vocabulary"},
  {id:"p5m84",question:"The firm has been _____ with a leading design agency for the rebrand.",options:["A) collaborate","B) collaborating","C) collaborated","D) collaboration"],answer:"B",explanation:"'Collaborating' is correct because 'has been collaborating' is the present perfect continuous, describing an ongoing activity that started in the past and continues to the present, appropriate for an in-progress rebranding project. 'Collaborate' is wrong because the base form cannot follow 'has been' to form a perfect continuous; a present participle is required. 'Collaborated' is wrong because 'has collaborated' (present perfect simple) would imply the collaboration is complete, but the continuous form better conveys the ongoing nature of the work. 'Collaboration' is wrong because it is a noun and cannot follow 'has been' as part of a verb phrase.",category:"Grammar"},
  {id:"p5m85",question:"The warehouse _____ to a new location next month to increase capacity.",options:["A) is relocating","B) relocate","C) has relocated","D) relocates"],answer:"A",explanation:"'Is relocating' is correct because the present continuous is used to describe a fixed and definite plan for the near future, especially when a future time marker ('next month') is present. 'Relocate' is wrong because the bare base form cannot serve as the finite verb of the sentence without an auxiliary. 'Has relocated' is wrong because the present perfect indicates the move has already been completed, but 'next month' shows the move is in the future. 'Relocates' is wrong because the simple present third-person singular form would imply the warehouse regularly relocates as a routine activity, not that it has a specific upcoming plan.",category:"Grammar"},
  {id:"p5m86",question:"The decision to outsource manufacturing was not taken _____.",options:["A) light","B) lightly","C) lightness","D) lightened"],answer:"B",explanation:"'Lightly' is correct because 'not taken lightly' is a fixed idiomatic expression meaning a decision was made only after serious consideration, and 'lightly' is an adverb modifying the past participle 'taken'. 'Light' is wrong because it is an adjective or noun and cannot modify the past participle 'taken' in this idiomatic expression. 'Lightness' is wrong because it is a noun meaning the quality of being light and cannot function as an adverb to modify 'taken'. 'Lightened' is wrong because it is a past tense verb meaning made lighter, and 'was not taken lightened' is not grammatical.",category:"Vocabulary"},
  {id:"p5m87",question:"Our strategic partner has confirmed _____ in the joint venture.",options:["A) participate","B) participating","C) participation","D) to participate"],answer:"C",explanation:"'Participation' is correct because 'confirmed participation' uses the noun as the object of 'confirmed', stating that the partner has officially declared their involvement as a fact. 'Participate' is wrong because the base verb form cannot serve as the direct object of 'confirmed'; a noun or gerund is needed. 'Participating' is wrong because while gerunds can be objects of 'confirm', 'confirmed participating' is less natural than 'confirmed participation' in formal business English. 'To participate' is wrong because 'confirm to participate' is not a standard structure; 'to participate' would follow verbs like 'agree', 'plan', or 'intend', not 'confirm'.",category:"Word Form"},
  {id:"p5m88",question:"_____ cost-cutting measures, the company managed to return to profitability.",options:["A) Despite adopting","B) In adopting","C) Through adopting","D) By adopting"],answer:"D",explanation:"'By adopting' is correct because 'by + gerund' expresses the means or method through which a result is achieved, meaning the cost-cutting measures were the tool used to return to profitability. 'Despite adopting' is wrong because 'despite' expresses contrast, implying the company returned to profitability even though it adopted cost-cutting measures, which suggests the measures were unhelpful. 'In adopting' is wrong because 'in + gerund' typically refers to the process or circumstance of doing something (e.g., 'in doing so'), not the means by which a result is achieved. 'Through adopting' is wrong because while 'through' can express means, 'by adopting' is the more natural and idiomatic expression of method in this context.",category:"Grammar"},
  {id:"p5m89",question:"The software platform is _____ to handle up to one million concurrent users.",options:["A) capable","B) capability","C) capably","D) capacitate"],answer:"A",explanation:"'Capable' is correct because 'capable of' is a fixed adjectival phrase meaning having the ability to, and an adjective is required after the linking verb 'is'. 'Capability' is wrong because it is a noun meaning the power or ability to do something; 'is capability' would need a different structure, such as 'the platform has the capability to handle'. 'Capably' is wrong because it is an adverb meaning in a competent manner, and it cannot serve as a predicate adjective after 'is'. 'Capacitate' is wrong because it is a verb meaning to enable or make capable, and 'is capacitate' is not grammatical.",category:"Vocabulary"},
  {id:"p5m90",question:"The company encourages employees to _____ professional development opportunities.",options:["A) pursue","B) pursuing","C) pursued","D) pursues"],answer:"A",explanation:"'Pursue' is correct because 'encourage someone to do something' requires the base infinitive after 'to', and 'pursue' means to actively seek or follow. 'Pursuing' is wrong because the gerund or present participle cannot follow 'to' in an infinitive construction; 'encourages employees to pursuing' is not grammatical. 'Pursued' is wrong because the past tense form cannot follow 'to' as an infinitive. 'Pursues' is wrong because the third-person singular present tense form cannot follow 'to' in an infinitive.",category:"Vocabulary"},
  {id:"p5m91",question:"The new regulations _____ all manufacturers to label allergens clearly.",options:["A) requires","B) require","C) required","D) requiring"],answer:"B",explanation:"'Require' is correct because 'regulations' is a plural noun and takes the base form of the verb in present simple, as the third-person plural does not add an 's'. 'Requires' is wrong because the 's' ending is for third-person singular subjects, but 'regulations' is plural. 'Required' is wrong because simple past implies the regulations are no longer in effect, but the context implies they are current and ongoing. 'Requiring' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m92",question:"The applicant _____ five languages, making her an ideal candidate for the role.",options:["A) is speaking","B) speaks","C) spoke","D) speak"],answer:"B",explanation:"'Speaks' is correct because the present simple is used to describe a permanent ability or characteristic of a person, and 'speaks' agrees with the third-person singular subject 'the applicant'. 'Is speaking' is wrong because the present continuous implies a temporary action happening right now, not a permanent language ability. 'Spoke' is wrong because simple past implies the applicant could speak five languages in the past but may no longer be able to. 'Speak' is wrong because the base form without 's' does not agree with the third-person singular subject 'the applicant'.",category:"Grammar"},
  {id:"p5m93",question:"Her work on the campaign was _____ praised by clients and colleagues alike.",options:["A) wide","B) widely","C) wideness","D) widen"],answer:"B",explanation:"'Widely' is correct because an adverb is needed to modify the passive adjective 'praised', indicating the extent or breadth of the praise, and 'widely praised' means praised by many people broadly. 'Wide' is wrong because it is an adjective and cannot modify a past participle or verb; it modifies nouns (e.g., 'a wide audience'). 'Wideness' is wrong because it is a noun meaning the quality of being wide and cannot function as an adverb. 'Widen' is wrong because it is a verb meaning to make wider, and it cannot function as an adverb modifier.",category:"Word Form"},
  {id:"p5m94",question:"The company has agreed to _____ the contract for another two years.",options:["A) renew","B) renewal","C) renewing","D) renewed"],answer:"A",explanation:"'Renew' is correct because 'agreed to + base infinitive' is the standard construction, where 'to' is part of the infinitive and 'renew' is the base form. 'Renewal' is wrong because it is a noun and cannot follow 'to' as an infinitive; you would say 'agreed to a renewal of the contract'. 'Renewing' is wrong because the gerund cannot directly follow 'to' in an infinitive construction; 'agreed to renewing' confuses the infinitive 'to' with the prepositional 'to' that precedes gerunds. 'Renewed' is wrong because the past tense or past participle form cannot follow 'to' as an infinitive.",category:"Vocabulary"},
  {id:"p5m95",question:"The new initiative is _____ to significantly reduce our carbon footprint.",options:["A) expended","B) expanded","C) expected","D) exported"],answer:"C",explanation:"'Expected' is correct because 'is expected to' is a passive construction using the past participle, expressing a projection or anticipation held by stakeholders about the initiative's future outcomes. 'Expended' is wrong because 'expended' means used up or spent (resources), and 'is expended to reduce' is not a meaningful construction. 'Expanded' is wrong because 'is expanded to' means the initiative is broadened or made larger, which does not logically connect to reducing a carbon footprint. 'Exported' is wrong because 'exported' refers to selling goods abroad, which is entirely unrelated to the context of an environmental initiative.",category:"Vocabulary"},
  {id:"p5m96",question:"The team worked _____ throughout the night to meet the morning deadline.",options:["A) tireless","B) tirelessly","C) tirelessness","D) tired"],answer:"B",explanation:"'Tirelessly' is correct because an adverb is needed to modify the verb 'worked', describing how the team worked, and 'tirelessly' means without becoming tired or stopping. 'Tireless' is wrong because it is an adjective and cannot modify a verb; it would modify a noun (e.g., 'a tireless worker'). 'Tirelessness' is wrong because it is a noun meaning the quality of being tireless and cannot function as an adverb to describe how the team worked. 'Tired' is wrong because it is an adjective meaning fatigued, and 'worked tired' would suggest the team was fatigued rather than describing how they worked.",category:"Word Form"},
  {id:"p5m97",question:"The CEO acknowledged that the transition _____ managed more smoothly.",options:["A) could be","B) could have been","C) should be","D) had been"],answer:"B",explanation:"'Could have been managed' is correct because this is a past modal expressing a missed opportunity — the transition was not managed as smoothly as it should have been, and 'could have been + past participle' describes an unrealized possibility in the past. 'Could be' is wrong because 'could be managed' is a present or general possibility, not a reference to a specific past event that did not go as planned. 'Should be' is wrong because 'should be managed' expresses a present or future obligation, not a reflection on a past event that has already occurred. 'Had been' is wrong because 'had been managed' (past perfect passive) would state a fact — that the transition had been managed in a certain way — rather than expressing the modal notion of an unrealized possibility.",category:"Grammar"},
  {id:"p5m98",question:"She was hired _____ to her impressive track record in digital marketing.",options:["A) owing","B) due","C) because","D) as a result"],answer:"A",explanation:"'Owing' is correct because 'owing to' is a formal prepositional phrase meaning 'because of', and 'owing to her impressive track record' correctly introduces the reason for her hiring before a noun phrase. 'Due' is wrong because 'due' alone is not a preposition; it must be followed by 'to' to form 'due to', and the sentence only has 'to' available as a preposition if 'due' precedes it, which would give 'due to to', which is ungrammatical. 'Because' is wrong because 'because' is a conjunction requiring a full clause (subject + verb), but 'her impressive track record' is a noun phrase. 'As a result' is wrong because 'as a result of' is the full prepositional phrase needed, but with only 'to' following in the sentence, the complete phrase cannot be formed.",category:"Grammar"},
  {id:"p5m99",question:"The data _____ that customer satisfaction has improved significantly.",options:["A) suggest","B) suggests","C) suggesting","D) suggested"],answer:"B",explanation:"'Suggests' is correct because in business and academic English, 'data' is increasingly treated as a singular mass noun, requiring the third-person singular 's' form in the present simple. 'Suggest' is wrong because while 'data' can be treated as plural in strict formal grammar (since it is the plural of 'datum'), in standard business English usage the singular verb 'suggests' is the conventional choice when 'data' functions as a mass noun. 'Suggesting' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary. 'Suggested' is wrong because simple past implies the data only made this suggestion at a specific past point, whereas the present simple describes what the data currently shows.",category:"Grammar"},
  {id:"p5m100",question:"The manager _____ approval before any overtime can be authorized.",options:["A) must give","B) gives","C) must be given","D) must given"],answer:"C",explanation:"'Must be given' is correct because the sentence means the manager must receive approval from a higher authority before overtime can proceed, so the passive modal ('must be + past participle') correctly positions the manager as the recipient of approval. 'Must give' is wrong because the active form 'must give approval' means the manager is the one granting approval to others, which reverses the intended power relationship. 'Gives' is wrong because the simple present active also implies the manager grants approval, not receives it. 'Must given' is wrong because the modal 'must' must be followed by the base form 'be', not the past participle 'given'; 'must given' is not grammatical.",category:"Grammar"},
  {id:"p5m101",question:"The performance review will _____ all aspects of the employee's contribution.",options:["A) encompass","B) encompasses","C) encompassing","D) encompassed"],answer:"A",explanation:"'Encompass' is correct because after the modal auxiliary 'will', the base form of the main verb is required. 'Encompasses' is wrong because the third-person singular 's' form cannot follow a modal auxiliary; base form is always required after modals. 'Encompassing' is wrong because the present participle cannot directly follow 'will' without the auxiliary 'be' (e.g., 'will be encompassing'). 'Encompassed' is wrong because the past participle would require 'be' before it to form a passive construction ('will be encompassed'), which would change the meaning entirely.",category:"Vocabulary"},
  {id:"p5m102",question:"The new hire _____ to her role surprisingly quickly.",options:["A) adapt","B) adapts","C) adapted","D) adapting"],answer:"C",explanation:"'Adapted' is correct because simple past tense is used to describe a completed past action — the new hire has already adjusted to her role, which is a finished process. 'Adapt' is wrong because the base form without a modal or auxiliary would only be grammatical in imperatives or certain subordinate clauses, not as the main verb of this declarative sentence. 'Adapts' is wrong because the present simple implies the new hire regularly and repeatedly adapts to her role, but the sentence describes a one-time completed adjustment. 'Adapting' is wrong because the present participle alone cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m103",question:"All grievance procedures must be _____ in accordance with company policy.",options:["A) handle","B) handled","C) handling","D) handles"],answer:"B",explanation:"'Handled' is correct because the sentence requires the passive modal construction 'must be + past participle', meaning the procedures must be processed by someone in accordance with policy. 'Handle' is wrong because the base form cannot follow 'must be' to form a passive; a past participle is needed. 'Handling' is wrong because 'must be handling' is a modal progressive, suggesting the procedures are expected to be in the process of handling something themselves, which is unnatural. 'Handles' is wrong because the third-person singular present form cannot follow 'must be'.",category:"Grammar"},
  {id:"p5m104",question:"The position has been _____ due to a lack of qualified applicants.",options:["A) unfilled","B) not filling","C) filling","D) no fill"],answer:"A",explanation:"'Unfilled' is correct because 'has been unfilled' uses the present perfect with the prefixed adjective 'unfilled', meaning the position has remained without an occupant up to now. 'Not filling' is wrong because 'has been not filling' is awkward and unidiomatic; the negation with 'un-' is more precise and natural. 'Filling' is wrong because 'has been filling' is present perfect progressive active, meaning the position has been filling something else, which makes no sense. 'No fill' is wrong because 'has been no fill' is not grammatical; 'no fill' is not a standard adjective or verb form.",category:"Vocabulary"},
  {id:"p5m105",question:"The distribution center will _____ operations around the clock.",options:["A) run","B) running","C) ran","D) runs"],answer:"A",explanation:"'Run' is correct because after the modal auxiliary 'will', the base form of the main verb is required, and 'run operations' means to carry out or manage operations. 'Running' is wrong because the present participle cannot directly follow 'will' without 'be'; 'will be running' would form a future progressive. 'Ran' is wrong because the simple past form cannot follow 'will' in any standard construction. 'Runs' is wrong because the third-person singular present form cannot follow a modal auxiliary.",category:"Grammar"},
  {id:"p5m106",question:"There has been an _____ increase in demand for cloud-based services.",options:["A) unprecedent","B) unprecedented","C) unprecedentedly","D) unprecedence"],answer:"B",explanation:"'Unprecedented' is correct because an adjective is needed to modify the noun 'increase', and 'unprecedented' means never having occurred before. 'Unprecedent' is wrong because it is not a standard English word; the correct adjective form is 'unprecedented', not 'unprecedent'. 'Unprecedentedly' is wrong because it is an adverb and cannot directly modify the noun 'increase'; it would modify an adjective or verb. 'Unprecedence' is wrong because it is not a recognized English word; there is no such noun form.",category:"Vocabulary"},
  {id:"p5m107",question:"The manager made it clear that _____ attendance at the workshop was expected.",options:["A) full","B) fully","C) fullness","D) fulled"],answer:"A",explanation:"'Full' is correct because an adjective is needed to modify the noun 'attendance', meaning everyone is expected to attend without exception. 'Fully' is wrong because it is an adverb and cannot directly modify a noun; it would modify an adjective or verb (e.g., 'fully committed'). 'Fullness' is wrong because it is a noun meaning the quality of being full and cannot modify another noun directly as an adjective. 'Fulled' is wrong because it is not a standard English word in common usage; 'full' does not have a past tense verb form.",category:"Word Form"},
  {id:"p5m108",question:"We had no choice but _____ the event due to the severe weather warning.",options:["A) cancel","B) to cancel","C) canceling","D) canceled"],answer:"B",explanation:"'To cancel' is correct because 'no choice but to + base infinitive' is a fixed construction where 'but' functions as a preposition equivalent to 'except', and the infinitive 'to cancel' follows. 'Cancel' is wrong because the bare infinitive without 'to' is used after 'but' only when the main clause already contains 'do' (e.g., 'we could do nothing but cancel'), but here 'to' is part of the fixed phrase 'no choice but to'. 'Canceling' is wrong because the gerund cannot follow 'no choice but to'; the infinitive is required in this fixed structure. 'Canceled' is wrong because the past tense form cannot follow 'to' as part of an infinitive.",category:"Grammar"},
  {id:"p5m109",question:"The manufacturer is working _____ to address the product quality issues.",options:["A) hard","B) hardly","C) hardship","D) hardened"],answer:"A",explanation:"'Hard' is correct because 'hard' functions as an adverb meaning with great effort when modifying a verb, and 'working hard' means putting in significant effort. 'Hardly' is wrong because 'hardly' means almost not or scarcely, creating the opposite meaning: the manufacturer is barely working to address the issues. 'Hardship' is wrong because it is a noun meaning difficulty or suffering and cannot modify the verb 'working'. 'Hardened' is wrong because it is an adjective meaning made tough or resistant, and it cannot function as an adverb to modify 'working'.",category:"Vocabulary"},
  {id:"p5m110",question:"The contract _____ have been signed before construction began.",options:["A) should","B) shall","C) might","D) can"],answer:"A",explanation:"'Should' is correct because 'should have been signed' is a past modal expressing a past obligation or expectation that was not fulfilled — the contract ought to have been signed but was not. 'Shall' is wrong because 'shall have been signed' would express a future perfect or formal future obligation, not a reflection on a past failure. 'Might' is wrong because 'might have been signed' expresses past possibility (perhaps it was signed), not an obligation that was missed. 'Can' is wrong because 'can have been signed' is generally not used to express past obligation; 'could have been signed' would express past possibility, not obligation.",category:"Modal"},
  {id:"p5m111",question:"The budget _____ for next year reflects the company's growth ambitions.",options:["A) propose","B) proposed","C) proposals","D) proposing"],answer:"B",explanation:"'Proposed' is correct because the past participle 'proposed' functions as a post-nominal adjective modifying 'budget', meaning 'the budget that has been proposed for next year', which is a reduced relative clause. 'Propose' is wrong because the base verb form cannot directly modify a noun as a post-nominal adjective; a past participle is needed for this function. 'Proposals' is wrong because it is a plural noun, and placing 'proposals' after 'budget' would create an ungrammatical noun-noun sequence where the roles are unclear. 'Proposing' is wrong because the present participle 'proposing' would describe a budget that is actively proposing something, not a budget that has been proposed.",category:"Grammar"},
  {id:"p5m112",question:"We _____ the contract if the vendor had met our quality standards.",options:["A) would renew","B) would have renewed","C) will renew","D) renew"],answer:"B",explanation:"'Would have renewed' is correct because this is a third conditional sentence (unrealized past condition), where 'if + past perfect' in the condition clause pairs with 'would have + past participle' in the result clause to describe what would have happened but did not. 'Would renew' is wrong because 'would + base form' is used in second conditional sentences about present or future hypotheticals, not about past unrealized events. 'Will renew' is wrong because 'will' expresses a real future intention, not a hypothetical past outcome. 'Renew' is wrong because the base form alone without a modal does not express the hypothetical or conditional nature of the outcome.",category:"Grammar"},
  {id:"p5m113",question:"The audit _____ that several internal controls were inadequate.",options:["A) revealed","B) reveals","C) is revealing","D) had reveal"],answer:"A",explanation:"'Revealed' is correct because simple past tense is appropriate for reporting the findings of a completed audit, describing what the audit showed at the time it was conducted. 'Reveals' is wrong because the simple present would imply the audit is currently and habitually revealing findings, whereas the audit is a specific completed event. 'Is revealing' is wrong because the present progressive implies the audit is currently in the process of revealing information, but the sentence describes past findings. 'Had reveal' is wrong because it is not grammatical; the past perfect would require the past participle 'revealed', not the base form, giving 'had revealed'.",category:"Grammar"},
  {id:"p5m114",question:"The assistant is tasked _____ coordinating all travel arrangements for the team.",options:["A) for","B) in","C) with","D) by"],answer:"C",explanation:"'With' is correct because 'tasked with' is the standard fixed collocation meaning assigned responsibility for, and it is always followed by the preposition 'with' plus a gerund. 'For' is wrong because 'tasked for' is not standard English; the correct preposition in this collocation is always 'with'. 'In' is wrong because 'tasked in' is not a recognized collocation; 'in' does not combine with 'tasked' to mean assigned. 'By' is wrong because 'tasked by' would indicate the agent who assigned the task, not the task itself (e.g., 'tasked by the manager'), making it grammatically wrong in this position.",category:"Preposition"},
  {id:"p5m115",question:"The company _____ 10 new offices since it went public three years ago.",options:["A) opens","B) opened","C) has opened","D) had opened"],answer:"C",explanation:"'Has opened' is correct because the present perfect is used to describe an accumulated result or action that occurred over a period from a specific past point ('since it went public') up to the present. 'Opens' is wrong because the simple present implies a regular habitual action (the company opens offices routinely), not a cumulative count since a past event. 'Opened' is wrong because simple past would suggest the openings happened only at one specific past moment, not over the entire period since going public. 'Had opened' is wrong because the past perfect describes an action completed before another past event, but here the reference point is the present ('since it went public' to now), not a past-before-past situation.",category:"Grammar"},
  {id:"p5m116",question:"The new regulation _____ all listed companies to publish sustainability reports.",options:["A) mandate","B) mandates","C) mandating","D) mandated"],answer:"B",explanation:"'Mandates' is correct because the subject 'the new regulation' is singular, requiring the third-person singular 's' form in the present simple to describe the regulation's current legal requirement. 'Mandate' is wrong because the base form without 's' does not agree with the singular subject 'the new regulation'. 'Mandating' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary. 'Mandated' is wrong because simple past would imply the regulation's requirement existed only in the past, but the context indicates it is a current, ongoing legal obligation.",category:"Grammar"},
  {id:"p5m117",question:"We regret _____ you that your application was unsuccessful.",options:["A) inform","B) to inform","C) informing","D) informed"],answer:"B",explanation:"'To inform' is correct because in formal business writing, 'regret + to + infinitive' is used to introduce bad news, expressing that the writer is sorry to deliver unwelcome information. 'Inform' is wrong because the bare base form cannot directly follow 'regret' without 'to'; 'regret inform' is not grammatical. 'Informing' is wrong because 'regret + gerund' means feeling sorry about something already done (e.g., 'we regret informing you' implies regret about a past act of informing), whereas 'regret to inform' introduces the bad news as something being done now. 'Informed' is wrong because the past tense or past participle form cannot follow 'regret' in either the infinitive or gerund construction.",category:"Grammar"},
  {id:"p5m118",question:"The company's _____ rate has improved since the new benefits package was introduced.",options:["A) retain","B) retaining","C) retention","D) retentive"],answer:"C",explanation:"'Retention' is correct because 'retention rate' is a compound noun in which 'retention' (the noun form) functions as a noun modifier, referring to the rate at which the company keeps employees. 'Retain' is wrong because it is the base form of a verb and cannot modify a noun in a compound noun structure; the noun form 'retention' is needed. 'Retaining' is wrong because the gerund can sometimes modify nouns in compound expressions, but 'retaining rate' is not a standard business term; 'retention rate' is the established phrase. 'Retentive' is wrong because it is an adjective meaning having the ability to retain things (often used for memory), and 'retentive rate' is not a recognized business expression.",category:"Word Form"},
  {id:"p5m119",question:"The draft contract _____ to both parties for review before the deadline.",options:["A) circulates","B) has been circulated","C) was circulating","D) will circulate"],answer:"B",explanation:"'Has been circulated' is correct because the present perfect passive indicates that someone has recently distributed the contract to both parties, with the relevance of this action still felt in the present context. 'Circulates' is wrong because the simple present active would mean the contract routinely distributes itself, which is not meaningful. 'Was circulating' is wrong because the past progressive active implies the contract was in the process of circulating at a specific past moment, and the active voice incorrectly makes the contract the agent of its own distribution. 'Will circulate' is wrong because the simple future active suggests the distribution has not yet happened, but the clause 'before the deadline' implies the distribution has already been completed.",category:"Grammar"},
  {id:"p5m120",question:"The team managed _____ the project within the original budget.",options:["A) complete","B) completed","C) completing","D) to complete"],answer:"D",explanation:"'To complete' is correct because 'managed to + base infinitive' is a fixed construction meaning succeeded in doing something, and the infinitive 'to complete' is always required after 'managed to'. 'Complete' is wrong because the bare base form without 'to' cannot follow 'managed' in this construction; 'managed complete' is not grammatical. 'Completed' is wrong because the past tense or past participle form cannot follow 'managed to'; only the base infinitive is used. 'Completing' is wrong because the gerund cannot follow 'managed to'; the infinitive is required in the fixed phrase 'manage to + infinitive'.",category:"Grammar"},
  {id:"p5m121",question:"The keynote address will focus _____ innovation in sustainable technology.",options:["A) on","B) in","C) with","D) at"],answer:"A",explanation:"'On' is correct because 'focus on' is the fixed phrasal verb meaning to concentrate on a specific topic, and 'on' is the only preposition used with 'focus' in this sense. 'In' is wrong because 'focus in' is not a standard English phrasal verb; 'in' does not collocate with 'focus' in this way. 'With' is wrong because 'focus with' is not a recognized collocation; 'with' is used after nouns like 'focus group' but not as a preposition after the verb 'focus'. 'At' is wrong because 'focus at' is not idiomatic; 'focus at' might be used in physical/optical contexts ('focus the lens at a point'), but not for concentrating on a topic.",category:"Preposition"},
  {id:"p5m122",question:"The charity gala raised _____ $1 million for medical research.",options:["A) over","B) above","C) more than","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because both 'over' and 'more than' are widely accepted and interchangeable in standard English when expressing that a quantity exceeds a given number. 'Over' alone is correct because it is a common preposition meaning exceeding a specific number or amount in informal and formal contexts. 'Above' alone is wrong because while 'above' can mean exceeding in some formal or technical contexts, it is less natural than 'over' or 'more than' when referring to a fundraising total. 'More than' alone is also correct, but since 'over' is equally valid, the answer must be 'both A and C'.",category:"Vocabulary"},
  {id:"p5m123",question:"Please _____ that all documents are properly filed before leaving the office.",options:["A) verify","B) verification","C) verified","D) verifying"],answer:"A",explanation:"'Verify' is correct because the sentence is an imperative (a polite instruction beginning with 'please'), which requires the base form of the main verb. 'Verification' is wrong because it is a noun and cannot serve as the main verb of an imperative sentence. 'Verified' is wrong because the past tense form cannot be used in an imperative construction; the base form is always required. 'Verifying' is wrong because the present participle cannot function as the main verb of an imperative sentence without an auxiliary.",category:"Vocabulary"},
  {id:"p5m124",question:"Her _____ leadership style helped bring the divided team together.",options:["A) inclusive","B) inclusion","C) inclusively","D) include"],answer:"A",explanation:"'Inclusive' is correct because an adjective is needed to modify the noun 'leadership style', and 'inclusive' means including everyone and making all feel valued. 'Inclusion' is wrong because it is a noun meaning the act of including, and placing it before 'leadership style' creates an ungrammatical compound noun in this context. 'Inclusively' is wrong because it is an adverb and cannot directly modify a noun; it would modify a verb or adjective. 'Include' is wrong because it is a verb meaning to contain or add, and it cannot function as an adjective to modify 'leadership style'.",category:"Word Form"},
  {id:"p5m125",question:"The team _____ of fifteen engineers, designers, and project managers.",options:["A) consists","B) consist","C) is consisted","D) consisting"],answer:"A",explanation:"'Consists' is correct because 'consist of' is an intransitive stative verb that takes no passive form, and it requires the third-person singular 's' to agree with the singular subject 'the team'. 'Consist' is wrong because the base form without 's' does not agree with the singular subject 'the team'; plural subjects or modal constructions would use 'consist'. 'Is consisted' is wrong because 'consist' is an intransitive verb that cannot be used in the passive voice; 'is consisted of' is not grammatical in standard English. 'Consisting' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m126",question:"She was _____ from her current role to head the new innovation lab.",options:["A) transferred","B) transfer","C) transferring","D) transfers"],answer:"A",explanation:"'Transferred' is correct because 'was transferred' is the simple past passive, meaning someone moved her from her current role, and the past participle 'transferred' follows 'was' in the passive construction. 'Transfer' is wrong because the base form cannot follow 'was' to form a passive; a past participle is required. 'Transferring' is wrong because 'was transferring' is the past progressive active, meaning she was in the process of transferring someone or something else, which reverses the intended meaning. 'Transfers' is wrong because the third-person singular present form cannot follow 'was' to form any standard grammatical construction.",category:"Grammar"},
  {id:"p5m127",question:"We appreciate your _____ in this matter and look forward to a resolution.",options:["A) cooperative","B) cooperate","C) cooperation","D) cooperatively"],answer:"C",explanation:"'Cooperation' is correct because a noun is needed after the possessive determiner 'your' to serve as the object of 'appreciate', and 'cooperation' is the abstract noun meaning working together. 'Cooperative' is wrong because it is an adjective meaning willing to cooperate; 'your cooperative' would imply 'your cooperative organization', not 'your act of cooperating'. 'Cooperate' is wrong because it is a verb and cannot follow the possessive 'your' to function as a noun. 'Cooperatively' is wrong because it is an adverb meaning in a cooperative manner and cannot serve as the object of 'appreciate'.",category:"Word Form"},
  {id:"p5m128",question:"The board has unanimously voted _____ the new acquisition.",options:["A) approve","B) to approve","C) approving","D) for approved"],answer:"B",explanation:"'To approve' is correct because 'voted to + base infinitive' is the standard construction expressing that the group decided through a vote to take a specific action. 'Approve' is wrong because the bare base form cannot follow 'voted' without 'to'; 'voted approve' is not grammatical. 'Approving' is wrong because the gerund cannot follow 'voted' in this construction; 'voted to approve' is the standard fixed phrase. 'For approved' is wrong because 'voted for approved' is not grammatical; if 'for' were used, it would need a noun ('voted for the approval of') or the gerund ('voted for approving'), but neither matches the standard idiom here.",category:"Grammar"},
  {id:"p5m129",question:"The client's _____ changes caused significant delays in the project timeline.",options:["A) lastly","B) last-minute","C) latest","D) lasting"],answer:"B",explanation:"'Last-minute' is correct because it is a compound adjective meaning done or occurring at the very end with little time to spare, which precisely describes changes that were made too close to the deadline. 'Lastly' is wrong because it is an adverb meaning finally in a sequence, and it cannot modify the noun 'changes'. 'Latest' is wrong because 'latest' means most recent (e.g., 'the latest report'), not changes made at the final moment; 'latest changes' would simply mean the most recent updates, not necessarily rushed ones. 'Lasting' is wrong because it is an adjective meaning enduring or long-term, which describes the opposite of a rushed, last-moment change.",category:"Vocabulary"},
  {id:"p5m130",question:"The report was _____ to include updated figures from the Q4 analysis.",options:["A) revised","B) revise","C) revising","D) revision"],answer:"A",explanation:"'Revised' is correct because 'was revised' is the simple past passive, indicating that someone updated the report, and the past participle 'revised' follows 'was' in the passive construction. 'Revise' is wrong because the base form cannot follow 'was' to form a passive; a past participle is required. 'Revising' is wrong because 'was revising' is the past progressive active, meaning the report was in the process of revising something, which makes no sense for an inanimate document. 'Revision' is wrong because it is a noun and cannot follow 'was' as part of a passive verb phrase.",category:"Grammar"},
  {id:"p5m131",question:"The director expressed _____ at the pace of the recovery.",options:["A) disappointed","B) disappoint","C) disappointment","D) disappointingly"],answer:"C",explanation:"'Disappointment' is correct because 'expressed disappointment' requires a noun as the direct object of the verb 'expressed', and 'disappointment' is the noun form meaning a feeling of dissatisfaction. 'Disappointed' is wrong because it is an adjective and cannot serve as the direct object of 'expressed'; you can 'express disappointment' but not 'express disappointed'. 'Disappoint' is wrong because it is the base form of a verb meaning to fail to meet expectations, and it cannot function as the noun object of 'expressed'. 'Disappointingly' is wrong because it is an adverb meaning in a disappointing manner and cannot serve as the noun object of 'expressed'.",category:"Word Form"},
  {id:"p5m132",question:"Negotiations are currently _____ between the two firms.",options:["A) underway","B) under","C) underwent","D) undergoing"],answer:"A",explanation:"'Underway' is correct because 'underway' is an adverb/adjective meaning in progress, and 'negotiations are currently underway' is a standard idiomatic expression in business English. 'Under' is wrong because 'under' alone is a preposition that requires a following noun (e.g., 'under discussion'), not the predicate adjective needed here after 'are'. 'Underwent' is wrong because it is the simple past tense of 'undergo', making 'negotiations are currently underwent' both grammatically incorrect and semantically illogical. 'Undergoing' is wrong because 'undergoing' is the present participle of 'undergo', and while 'are undergoing negotiations' is grammatical, it would require rearranging the sentence; 'are currently undergoing' without an object is incomplete.",category:"Vocabulary"},
  {id:"p5m133",question:"The _____ agreement ensures all parties share equally in profits and losses.",options:["A) partnership","B) partnering","C) partner","D) partnered"],answer:"A",explanation:"'Partnership' is correct because 'partnership agreement' is a standard compound noun in business and legal English, where 'partnership' (the noun form) modifies 'agreement' to indicate the type of legal contract. 'Partnering' is wrong because the gerund 'partnering' modifying a noun would create 'partnering agreement', which is non-standard and not the recognized legal term. 'Partner' is wrong because while 'partner' can modify nouns in some compounds (e.g., 'partner company'), 'partner agreement' is not the standard legal term; 'partnership agreement' is the established phrase. 'Partnered' is wrong because the past participle 'partnered' used before 'agreement' would describe a 'partnered agreement', implying the agreement is paired with something, which is not the intended meaning.",category:"Vocabulary"},
  {id:"p5m134",question:"The new product range has been _____ well by the target demographic.",options:["A) receive","B) receiving","C) received","D) reception"],answer:"C",explanation:"'Received' is correct because 'has been received' is the present perfect passive, indicating that the target demographic has given a positive response to the product range, and 'received well' means it was welcomed positively. 'Receive' is wrong because the base form cannot follow 'has been' to form a passive perfect; a past participle is required. 'Receiving' is wrong because 'has been receiving' is present perfect progressive active, meaning the product range has been accepting something, which makes no sense for an inanimate range of products. 'Reception' is wrong because it is a noun and cannot follow 'has been' as part of a verb phrase.",category:"Grammar"},
  {id:"p5m135",question:"She _____ the job offer after learning more about the company culture.",options:["A) declines","B) declined","C) was declining","D) has decline"],answer:"B",explanation:"'Declined' is correct because simple past tense is used to describe a specific completed decision made in the past, and 'declined' indicates she turned down the offer at that point. 'Declines' is wrong because the simple present implies this is a habitual action or is happening now, but the sentence describes a specific past event. 'Was declining' is wrong because the past progressive suggests the action was ongoing or in progress at a past moment, not that it was a discrete completed decision. 'Has decline' is wrong because the present perfect requires the past participle 'declined', not the base form 'decline'; 'has declined' would be the correct present perfect form.",category:"Grammar"},
  {id:"p5m136",question:"The proposal has been _____ pending further market research.",options:["A) putting on hold","B) put on hold","C) puts on hold","D) put in hold"],answer:"B",explanation:"'Put on hold' is correct because 'has been put on hold' is the present perfect passive using the past participle 'put', and 'put on hold' is the correct fixed phrasal verb meaning temporarily postponed. 'Putting on hold' is wrong because 'has been putting on hold' is present perfect progressive active, implying the proposal has been actively postponing something else. 'Puts on hold' is wrong because the third-person singular present active cannot follow 'has been' to form a passive. 'Put in hold' is wrong because the correct preposition in this phrasal verb is 'on', not 'in'; 'put in hold' is not standard English.",category:"Vocabulary"},
  {id:"p5m137",question:"The company _____ its operations to 12 new countries over the past five years.",options:["A) extending","B) extends","C) has extended","D) was extending"],answer:"C",explanation:"'Has extended' is correct because the present perfect is used to describe a cumulative action or achievement that occurred over a defined past period leading up to the present ('over the past five years'). 'Extending' is wrong because the present participle alone cannot serve as the finite main verb of the sentence without an auxiliary. 'Extends' is wrong because the simple present implies the company routinely extends its operations as an ongoing habit, not that it has achieved this expansion over the past five years. 'Was extending' is wrong because the past progressive describes an action in progress at a specific past moment, not a cumulative achievement over several years.",category:"Grammar"},
  {id:"p5m138",question:"The workshop is _____ to participants who register before June 1st.",options:["A) free","B) freely","C) freedom","D) freed"],answer:"A",explanation:"'Free' is correct because a predicate adjective is needed after the linking verb 'is', and 'free to participants' means the workshop costs nothing for those who register early. 'Freely' is wrong because it is an adverb meaning without restriction or without charge in some contexts, but it cannot serve as a predicate adjective after 'is'; 'is freely' would require a verb or adjective to modify. 'Freedom' is wrong because it is a noun meaning the state of being free, and 'is freedom' would mean the workshop is freedom, which is not logical. 'Freed' is wrong because it is the past tense of 'free' used as a verb (meaning released) or a past participle adjective meaning liberated from something, neither of which fits the intended meaning of being available at no cost.",category:"Word Form"},
  {id:"p5m139",question:"The policy change _____ approval from at least two-thirds of the board.",options:["A) require","B) requires","C) required","D) requiring"],answer:"B",explanation:"'Requires' is correct because the subject 'the policy change' is singular, requiring the third-person singular 's' form in the present simple to state a current ongoing condition. 'Require' is wrong because the base form without 's' is used with plural subjects or in modal constructions, but 'the policy change' is singular. 'Required' is wrong because simple past implies the requirement existed only in the past, whereas the sentence describes a standing rule that currently applies. 'Requiring' is wrong because the present participle cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m140",question:"The manager _____ the issue to senior management after a third complaint.",options:["A) escalated","B) escalate","C) escalating","D) escalation"],answer:"A",explanation:"'Escalated' is correct because simple past tense is used to describe a specific completed action that the manager took at a defined past moment (after a third complaint). 'Escalate' is wrong because the bare base form cannot serve as the finite verb of the sentence in this declarative context without an auxiliary. 'Escalating' is wrong because the present participle alone cannot serve as the finite main verb without an auxiliary. 'Escalation' is wrong because it is a noun meaning the act of escalating and cannot function as the main verb of the sentence.",category:"Vocabulary"},
  {id:"p5m141",question:"The committee _____ its findings to the board at next month's meeting.",options:["A) present","B) will present","C) presented","D) presenting"],answer:"B",explanation:"'Will present' is correct because the sentence refers to a planned future action indicated by 'at next month's meeting', and 'will + base form' expresses a definite future intention. 'Present' is wrong because the simple present base form does not convey the future nature of the planned presentation, though it could be used with a time adverb in scheduled events; 'will present' is more explicit. 'Presented' is wrong because simple past indicates the presentation has already taken place, which contradicts 'next month's meeting'. 'Presenting' is wrong because the present participle alone cannot serve as the finite main verb of the sentence without an auxiliary.",category:"Grammar"},
  {id:"p5m142",question:"The staff member has been _____ for leading the new diversity initiative.",options:["A) nominate","B) nominated","C) nominating","D) nomination"],answer:"B",explanation:"'Nominated' is correct because 'has been nominated' is the present perfect passive using the past participle, indicating that someone has recently put the staff member forward for this role. 'Nominate' is wrong because the base form cannot follow 'has been' to form a passive perfect; a past participle is required. 'Nominating' is wrong because 'has been nominating' is the present perfect progressive active, implying the staff member has been putting others forward for nomination. 'Nomination' is wrong because it is a noun and cannot follow 'has been' as part of a verb phrase.",category:"Grammar"},
  {id:"p5m143",question:"The firm gained _____ recognition after winning the industry excellence award.",options:["A) wide","B) widely","C) wider","D) widest"],answer:"A",explanation:"'Wide' is correct because in the compound adjective phrase 'wide recognition', 'wide' functions as an adjective modifying the noun 'recognition', meaning broad or extensive recognition. 'Widely' is wrong because 'widely' is an adverb and would normally modify a verb (e.g., 'the product is widely used'), not a noun directly, though in some fixed expressions it may precede adjectives. 'Wider' is wrong because the comparative form 'wider recognition' would require a comparison with something else (e.g., 'wider recognition than before'), which is not indicated in the sentence. 'Widest' is wrong because the superlative 'widest' requires a defined comparison group (e.g., 'the widest recognition in the industry'), which is absent.",category:"Word Form"},
  {id:"p5m144",question:"The division _____ to achieve a 20% increase in output this fiscal year.",options:["A) targets","B) targeting","C) is targeting","D) both A and C"],answer:"D",explanation:"'Both A and C' is correct because both 'targets' (simple present, describing the division's stated goal) and 'is targeting' (present continuous, describing the division's current active pursuit of the goal) are grammatically correct and meaningful in context. 'Targets' alone is correct because the simple present can describe an organizational goal or objective. 'Targeting' alone is wrong because the present participle cannot serve as the finite main verb without an auxiliary. 'Is targeting' alone is correct because the present continuous describes an ongoing current effort toward the goal, making it equally valid.",category:"Grammar"},
  {id:"p5m145",question:"The sales figures have been _____ over three consecutive quarters.",options:["A) climb","B) climbed","C) climbing","D) climbable"],answer:"C",explanation:"'Climbing' is correct because 'have been climbing' is the present perfect continuous, describing a trend that has been ongoing progressively over three consecutive quarters up to the present. 'Climb' is wrong because the base form cannot follow 'have been' to form a perfect continuous; the present participle is required. 'Climbed' is wrong because 'have been climbed' would be the present perfect passive, which is semantically inappropriate since sales figures are not being climbed by something. 'Climbable' is wrong because it is an adjective meaning capable of being climbed and cannot serve as part of a verb phrase after 'have been'.",category:"Grammar"},
  {id:"p5m146",question:"She took _____ a new project despite her already heavy workload.",options:["A) up","B) on","C) in","D) over"],answer:"B",explanation:"'On' is correct because 'take on' is the fixed phrasal verb meaning to accept a new responsibility, challenge, or task. 'Up' is wrong because 'take up' means to begin a hobby or pursue an interest (e.g., 'take up golf'), not to accept a work responsibility; 'take up a project' sounds unnatural in this context. 'In' is wrong because 'take in' means to absorb information, deceive, or accommodate (e.g., 'take in a show'), not to accept a new project. 'Over' is wrong because 'take over' means to assume control of something from someone else (e.g., 'take over the company'), not simply to accept an additional project.",category:"Vocabulary"},
  {id:"p5m147",question:"The study _____ that remote workers are generally more productive.",options:["A) found","B) finds","C) has find","D) is finding"],answer:"A",explanation:"'Found' is correct because simple past tense is used to report the results of a completed study, indicating that the study reached this conclusion at the time it was conducted. 'Finds' is wrong because the simple present implies the study is currently and repeatedly discovering this fact as a habitual process, whereas a study is a specific completed piece of research. 'Has find' is wrong because the present perfect requires the past participle 'found', not the base form 'find'; 'has found' would be the correct present perfect form. 'Is finding' is wrong because the present progressive implies the study is currently in the process of discovering something, but a completed study's findings are reported in the past tense.",category:"Grammar"},
  {id:"p5m148",question:"The training was specifically designed _____ address the team's skill gaps.",options:["A) to","B) for","C) in order","D) so that"],answer:"A",explanation:"'To' is correct because 'designed to + base infinitive' is the standard structure for expressing purpose with a past participle, and 'to address' is the infinitive of purpose. 'For' is wrong because 'designed for' would need to be followed by a noun (e.g., 'designed for professionals'), not the base verb 'address'; 'designed for address' is not grammatical. 'In order' is wrong because 'in order to' is the full expression for purpose, but 'in order' alone before 'address' is incomplete; the full phrase 'in order to address' would be correct but is not among the given options as a complete choice. 'So that' is wrong because 'so that' introduces a clause with a subject and modal verb (e.g., 'so that the team could address gaps'), but 'address the team's skill gaps' without a subject and auxiliary is not a full clause.",category:"Grammar"},
  {id:"p5m149",question:"The annual report was _____ to all shareholders via the company website.",options:["A) distribute","B) distributing","C) distributed","D) distributes"],answer:"C",explanation:"'Distributed' is correct because 'was distributed' is the simple past passive, indicating that someone sent the annual report to all shareholders, and the past participle 'distributed' follows 'was' in the passive construction. 'Distribute' is wrong because the base form cannot follow 'was' to form a passive; a past participle is required. 'Distributing' is wrong because 'was distributing' is the past progressive active, meaning the report was in the process of distributing something, which makes no sense for a document. 'Distributes' is wrong because the third-person singular present form cannot follow 'was' in any standard grammatical construction.",category:"Grammar"},
  {id:"p5m150",question:"The team is _____ on a tight deadline to complete the final proposal.",options:["A) working","B) work","C) worked","D) works"],answer:"A",explanation:"'Working' is correct because 'is working on' is the present continuous, describing an action currently in progress, and 'working on a tight deadline' is a natural idiomatic expression. 'Work' is wrong because the base form alone cannot follow 'is' to form a continuous tense; the present participle is required. 'Worked' is wrong because 'is worked' would form a passive voice, meaning the team is being worked on by something, which does not make sense in this context. 'Works' is wrong because the third-person singular present form cannot follow 'is' as part of a verb phrase; 'is works' is not grammatical.",category:"Grammar"}
];
